import { useEffect, useState, useRef } from 'react'
import { advancedProctoringAPI } from '../lib/advancedAPIs'
import { Camera, AlertTriangle, Eye, Brain, Activity } from 'lucide-react'

interface ProctoringAnalysis {
  violations: Array<{
    type: string
    severity: string
    message: string
    timestamp: number
    confidence: number
  }>
  metrics: {
    face_confidence: number
    gaze_horizontal: number
    gaze_vertical: number
    attention_score: number
    emotion: string
    emotion_confidence: number
    eye_aspect_ratio: number
    head_pose: {
      pitch: number
      yaw: number
      roll: number
    }
    brightness: number
  }
  state: {
    risk_score: number
    violation_count: number
    attention_level: string
    recommendation: string
  }
}

interface AdvancedProctoringMonitorProps {
  sessionId: string
  examId: string
  studentId: string
  onTerminate?: () => void
}

export default function AdvancedProctoringMonitor({
  sessionId,
  examId,
  studentId,
  onTerminate
}: AdvancedProctoringMonitorProps) {
  const [isActive, setIsActive] = useState(false)
  const [analysis, setAnalysis] = useState<ProctoringAnalysis | null>(null)
  const [calibrating, setCalibrating] = useState(false)
  const [calibrationProgress, setCalibrationProgress] = useState(0)
  const videoRef = useRef<HTMLVideoElement>(null)
  const canvasRef = useRef<HTMLCanvasElement>(null)
  const streamRef = useRef<MediaStream | null>(null)
  const frameIntervalRef = useRef<number | null>(null)

  useEffect(() => {
    startProctoring()
    return () => {
      stopProctoring()
    }
  }, [])

  const startProctoring = async () => {
    try {
      // Start proctoring session
      const result = await advancedProctoringAPI.startSession({
        session_id: sessionId,
        exam_id: examId,
        student_id: studentId,
        proctoring_level: 'STRICT'
      })

      if (result.calibration_required_frames) {
        setCalibrating(true)
        setCalibrationProgress(0)
      }

      // Get video stream
      const stream = await navigator.mediaDevices.getUserMedia({
        video: { width: 1280, height: 720, facingMode: 'user' },
        audio: true
      })

      streamRef.current = stream

      if (videoRef.current) {
        videoRef.current.srcObject = stream
        await videoRef.current.play()
      }

      setIsActive(true)

      // Start frame analysis every 1 second
      frameIntervalRef.current = window.setInterval(() => {
        captureAndAnalyze()
      }, 1000)

    } catch (error) {
      console.error('Failed to start proctoring:', error)
    }
  }

  const stopProctoring = async () => {
    if (frameIntervalRef.current) {
      clearInterval(frameIntervalRef.current)
    }

    if (streamRef.current) {
      streamRef.current.getTracks().forEach(track => track.stop())
    }

    if (isActive) {
      await advancedProctoringAPI.stopSession(sessionId)
    }

    setIsActive(false)
  }

  const captureAndAnalyze = async () => {
    if (!videoRef.current || !canvasRef.current || !isActive) return

    const video = videoRef.current
    const canvas = canvasRef.current
    const ctx = canvas.getContext('2d')

    if (!ctx) return

    // Capture frame
    canvas.width = video.videoWidth
    canvas.height = video.videoHeight
    ctx.drawImage(video, 0, 0)

    // Convert to base64
    const frameData = canvas.toDataURL('image/jpeg', 0.8).split(',')[1]

    // Analyze frame
    try {
      const result = await advancedProctoringAPI.analyzeFrame({
        session_id: sessionId,
        frame_data: frameData,
        timestamp: Date.now()
      })

      setAnalysis(result)

      // Update calibration progress
      if (calibrating && result.calibration_progress !== undefined) {
        setCalibrationProgress(result.calibration_progress)
        if (result.calibration_progress >= 100) {
          setCalibrating(false)
        }
      }

      // Check for critical violations
      if (result.state.risk_score >= 85 && result.state.recommendation === 'TERMINATE_EXAM') {
        onTerminate?.()
      }

    } catch (error) {
      console.error('Frame analysis failed:', error)
    }
  }

  const getRiskColor = (score: number) => {
    if (score < 30) return 'text-green-500'
    if (score < 50) return 'text-yellow-500'
    if (score < 70) return 'text-orange-500'
    return 'text-red-500'
  }

  const getEmotionEmoji = (emotion: string) => {
    const emotions: Record<string, string> = {
      neutral: '≡ƒÿÉ',
      focused: '≡ƒÄ»',
      confused: '≡ƒÿò',
      stressed: '≡ƒÿ░',
      suspicious: '≡ƒñ¿',
      happy: '≡ƒÿè'
    }
    return emotions[emotion] || '≡ƒÿÉ'
  }

  return (
    <div className="space-y-4">
      {/* Calibration Banner */}
      {calibrating && (
        <div className="bg-blue-50 border border-blue-200 rounded-lg p-4">
          <div className="flex items-center gap-3">
            <Brain className="w-5 h-5 text-blue-600 animate-pulse" />
            <div className="flex-1">
              <h3 className="text-sm font-medium text-blue-900">Calibrating AI Baseline</h3>
              <p className="text-xs text-blue-700">Establishing your normal behavior pattern...</p>
              <div className="mt-2 bg-blue-200 rounded-full h-2 overflow-hidden">
                <div 
                  className="bg-blue-600 h-full transition-all duration-300"
                  style={{ width: `${calibrationProgress}%` }}
                />
              </div>
              <p className="text-xs text-blue-600 mt-1">{calibrationProgress}%</p>
            </div>
          </div>
        </div>
      )}

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-4">
        {/* Video Feed */}
        <div className="lg:col-span-2">
          <div className="bg-white rounded-lg shadow-sm overflow-hidden">
            <div className="bg-gradient-to-r from-blue-600 to-purple-600 px-4 py-2 flex items-center justify-between">
              <div className="flex items-center gap-2">
                <Camera className="w-4 h-4 text-white" />
                <span className="text-white text-sm font-medium">Live Monitoring</span>
                {isActive && (
                  <span className="flex items-center gap-1 text-xs text-white/90">
                    <span className="w-2 h-2 bg-red-500 rounded-full animate-pulse" />
                    Recording
                  </span>
                )}
              </div>
            </div>
            <div className="relative bg-gray-900 aspect-video">
              <video
                ref={videoRef}
                className="w-full h-full object-cover"
                autoPlay
                playsInline
                muted
              />
              <canvas ref={canvasRef} className="hidden" />
              
              {/* Risk Score Overlay */}
              {analysis && (
                <div className="absolute top-4 right-4 bg-black/80 rounded-lg px-4 py-2 backdrop-blur-sm">
                  <div className="text-center">
                    <div className={`text-2xl font-bold ${getRiskColor(analysis.state.risk_score)}`}>
                      {analysis.state.risk_score}
                    </div>
                    <div className="text-xs text-white/70">Risk Score</div>
                  </div>
                </div>
              )}
            </div>
          </div>
        </div>

        {/* Real-Time Metrics */}
        <div className="space-y-4">
          {/* Attention Score */}
          {analysis && (
            <>
              <div className="bg-white rounded-lg shadow-sm p-4">
                <div className="flex items-center gap-2 mb-3">
                  <Eye className="w-4 h-4 text-blue-600" />
                  <h3 className="text-sm font-medium text-gray-900">Attention</h3>
                </div>
                <div className="space-y-2">
                  <div className="flex justify-between items-center">
                    <span className="text-2xl font-bold text-blue-600">
                      {Math.round(analysis.metrics.attention_score)}%
                    </span>
                    <span className={`text-xs px-2 py-1 rounded-full ${
                      analysis.metrics.attention_score > 80 ? 'bg-green-100 text-green-700' :
                      analysis.metrics.attention_score > 60 ? 'bg-yellow-100 text-yellow-700' :
                      'bg-red-100 text-red-700'
                    }`}>
                      {analysis.state.attention_level}
                    </span>
                  </div>
                  <div className="bg-gray-200 rounded-full h-2">
                    <div 
                      className="bg-blue-600 h-full rounded-full transition-all"
                      style={{ width: `${analysis.metrics.attention_score}%` }}
                    />
                  </div>
                </div>
              </div>

              {/* Emotion Detection */}
              <div className="bg-white rounded-lg shadow-sm p-4">
                <div className="flex items-center gap-2 mb-3">
                  <Brain className="w-4 h-4 text-purple-600" />
                  <h3 className="text-sm font-medium text-gray-900">Emotion</h3>
                </div>
                <div className="text-center">
                  <div className="text-4xl mb-2">
                    {getEmotionEmoji(analysis.metrics.emotion)}
                  </div>
                  <div className="text-sm font-medium text-gray-900 capitalize">
                    {analysis.metrics.emotion}
                  </div>
                  <div className="text-xs text-gray-500">
                    {Math.round(analysis.metrics.emotion_confidence * 100)}% confidence
                  </div>
                </div>
              </div>

              {/* Head Pose */}
              <div className="bg-white rounded-lg shadow-sm p-4">
                <div className="flex items-center gap-2 mb-3">
                  <Activity className="w-4 h-4 text-green-600" />
                  <h3 className="text-sm font-medium text-gray-900">Head Pose</h3>
                </div>
                <div className="space-y-2 text-xs">
                  <div className="flex justify-between">
                    <span className="text-gray-600">Pitch</span>
                    <span className="font-medium">{analysis.metrics.head_pose.pitch.toFixed(1)}┬░</span>
                  </div>
                  <div className="flex justify-between">
                    <span className="text-gray-600">Yaw</span>
                    <span className="font-medium">{analysis.metrics.head_pose.yaw.toFixed(1)}┬░</span>
                  </div>
                  <div className="flex justify-between">
                    <span className="text-gray-600">Roll</span>
                    <span className="font-medium">{analysis.metrics.head_pose.roll.toFixed(1)}┬░</span>
                  </div>
                </div>
              </div>

              {/* Gaze Direction */}
              <div className="bg-white rounded-lg shadow-sm p-4">
                <div className="flex items-center gap-2 mb-3">
                  <Eye className="w-4 h-4 text-indigo-600" />
                  <h3 className="text-sm font-medium text-gray-900">Gaze Direction</h3>
                </div>
                <div className="space-y-2 text-xs">
                  <div className="flex justify-between">
                    <span className="text-gray-600">Horizontal</span>
                    <span className="font-medium">{analysis.metrics.gaze_horizontal.toFixed(1)}┬░</span>
                  </div>
                  <div className="flex justify-between">
                    <span className="text-gray-600">Vertical</span>
                    <span className="font-medium">{analysis.metrics.gaze_vertical.toFixed(1)}┬░</span>
                  </div>
                </div>
              </div>
            </>
          )}
        </div>
      </div>

      {/* Violations */}
      {analysis && analysis.violations.length > 0 && (
        <div className="bg-red-50 border border-red-200 rounded-lg p-4">
          <div className="flex items-center gap-2 mb-3">
            <AlertTriangle className="w-4 h-4 text-red-600" />
            <h3 className="text-sm font-medium text-red-900">
              Recent Violations ({analysis.violations.length})
            </h3>
          </div>
          <div className="space-y-2">
            {analysis.violations.slice(0, 3).map((violation, index) => (
              <div
                key={index}
                className="flex items-start gap-2 text-sm bg-white rounded p-2"
              >
                <div className={`w-1.5 h-1.5 rounded-full mt-1.5 ${
                  violation.severity === 'critical' ? 'bg-red-500' :
                  violation.severity === 'high' ? 'bg-orange-500' :
                  violation.severity === 'medium' ? 'bg-yellow-500' :
                  'bg-blue-500'
                }`} />
                <div className="flex-1">
                  <div className="font-medium text-gray-900">{violation.type}</div>
                  <div className="text-xs text-gray-600">{violation.message}</div>
                  <div className="text-xs text-gray-500 mt-1">
                    {Math.round(violation.confidence * 100)}% confidence
                  </div>
                </div>
              </div>
            ))}
          </div>
        </div>
      )}

      {/* AI Recommendation */}
      {analysis && analysis.state.recommendation && (
        <div className={`rounded-lg p-4 ${
          analysis.state.recommendation === 'TERMINATE_EXAM' ? 'bg-red-50 border border-red-200' :
          analysis.state.recommendation === 'TEACHER_ALERT' ? 'bg-orange-50 border border-orange-200' :
          analysis.state.recommendation === 'WARNING' ? 'bg-yellow-50 border border-yellow-200' :
          'bg-blue-50 border border-blue-200'
        }`}>
          <div className="flex items-center gap-2">
            <Brain className={`w-4 h-4 ${
              analysis.state.recommendation === 'TERMINATE_EXAM' ? 'text-red-600' :
              analysis.state.recommendation === 'TEACHER_ALERT' ? 'text-orange-600' :
              analysis.state.recommendation === 'WARNING' ? 'text-yellow-600' :
              'text-blue-600'
            }`} />
            <div>
              <div className="text-sm font-medium">AI Recommendation</div>
              <div className="text-xs mt-1">{analysis.state.recommendation.replace(/_/g, ' ')}</div>
            </div>
          </div>
        </div>
      )}
    </div>
  )
}

import { useState, useEffect, useRef } from 'react'
import { motion, AnimatePresence } from 'framer-motion'
import { MessageSquare, Send, X } from 'lucide-react'
import { WebSocketClient } from '../lib/websocket'

interface ChatMessage {
  message_id: string
  type: 'student_message' | 'teacher_reply'
  student_id?: string
  student_name?: string
  teacher_id?: string
  teacher_name?: string
  message: string
  timestamp: string
}

interface ExamChatProps {
  wsClientRef: React.RefObject<WebSocketClient | null>
  userId: string
  userName: string
  role: 'student' | 'teacher'
  examId: string
  forStudentId?: string
}

export default function ExamChat({
  wsClientRef,
  userId,
  userName,
  role,
  examId,
  forStudentId,
}: ExamChatProps) {
  const [isOpen, setIsOpen] = useState(false)
  const [messages, setMessages] = useState<ChatMessage[]>([])
  const [input, setInput] = useState('')
  const [unreadCount, setUnreadCount] = useState(0)
  const messagesEndRef = useRef<HTMLDivElement>(null)
  const inputRef = useRef<HTMLTextAreaElement>(null)

  const isTeacher = role === 'teacher'

  // Register WebSocket handlers
  useEffect(() => {
    const ws = wsClientRef.current
    if (!ws) return

    const handleStudentMessage = (data: any) => {
      const msg: ChatMessage = {
        message_id: data.message_id || `msg_${Date.now()}`,
        type: 'student_message',
        student_id: data.student_id,
        student_name: data.student_name || data.student_id,
        message: data.message,
        timestamp: data.timestamp,
      }
      setMessages(prev => [...prev, msg])
      if (!isOpen) setUnreadCount(c => c + 1)
    }

    const handleTeacherReply = (data: any) => {
      const msg: ChatMessage = {
        message_id: data.message_id || `reply_${Date.now()}`,
        type: 'teacher_reply',
        student_id: data.student_id,
        teacher_id: data.teacher_id,
        teacher_name: data.teacher_name || data.teacher_id,
        message: data.message,
        timestamp: data.timestamp,
      }
      setMessages(prev => [...prev, msg])
      if (!isOpen) setUnreadCount(c => c + 1)
    }

    const handleMessageHistory = (data: any) => {
      if (Array.isArray(data.messages)) {
        setMessages(data.messages)
      }
    }

    ws.on('student_message', handleStudentMessage)
    ws.on('teacher_reply', handleTeacherReply)
    ws.on('message_history', handleMessageHistory)

    return () => {
      ws.off('student_message', handleStudentMessage)
      ws.off('teacher_reply', handleTeacherReply)
      ws.off('message_history', handleMessageHistory)
    }
  }, [wsClientRef.current, isOpen])

  // Scroll to bottom on new messages
  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' })
  }, [messages])

  // Reset unread when opening
  useEffect(() => {
    if (isOpen) setUnreadCount(0)
  }, [isOpen])

  const sendMessage = () => {
    const text = input.trim()
    if (!text || !wsClientRef.current) return

    if (isTeacher) {
      if (!forStudentId) return
      wsClientRef.current.send({
        type: 'teacher_reply',
        exam_id: examId,
        student_id: forStudentId,
        teacher_name: userName,
        message: text,
        timestamp: new Date().toISOString(),
      })
    } else {
      wsClientRef.current.send({
        type: 'student_message',
        exam_id: examId,
        student_name: userName,
        message: text,
        timestamp: new Date().toISOString(),
      })
    }

    setInput('')
    if (inputRef.current) inputRef.current.focus()
  }

  const showMessage = (msg: ChatMessage) => {
    if (isTeacher && forStudentId) {
      return (
        msg.student_id === forStudentId ||
        (msg.type === 'teacher_reply' && msg.student_id === forStudentId)
      )
    }
    return true
  }

  const filteredMessages = messages.filter(showMessage)

  const formatTime = (ts: string) => {
    try {
      return new Date(ts).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })
    } catch {
      return ''
    }
  }

  return (
    <>
      {/* Chat Toggle Button */}
      <button
        onClick={() => setIsOpen(!isOpen)}
        className="relative p-2.5 rounded-xl bg-gray-800 hover:bg-gray-700 border border-gray-700 text-gray-300 hover:text-white transition-all"
        title={isOpen ? 'Close chat' : 'Open chat'}
      >
        <MessageSquare className="w-5 h-5" />
        {unreadCount > 0 && (
          <span className="absolute -top-1 -right-1 w-5 h-5 bg-red-500 text-white text-xs rounded-full flex items-center justify-center font-bold animate-pulse">
            {unreadCount > 9 ? '9+' : unreadCount}
          </span>
        )}
      </button>

      {/* Chat Panel */}
      <AnimatePresence>
        {isOpen && (
          <motion.div
            initial={{ opacity: 0, y: 20, scale: 0.95 }}
            animate={{ opacity: 1, y: 0, scale: 1 }}
            exit={{ opacity: 0, y: 20, scale: 0.95 }}
            transition={{ type: 'spring', bounce: 0.2 }}
            className="fixed bottom-4 right-4 z-[9999] w-80 sm:w-96 bg-gray-900 border border-gray-700 rounded-2xl shadow-2xl flex flex-col"
            style={{ maxHeight: 'calc(100vh - 120px)' }}
          >
            {/* Header */}
            <div className="flex items-center justify-between px-4 py-3 border-b border-gray-700 bg-gray-800/50 rounded-t-2xl">
              <div className="flex items-center gap-2">
                <MessageSquare className="w-4 h-4 text-blue-400" />
                <span className="text-sm font-semibold text-gray-200">
                  {isTeacher ? 'Student Messages' : 'Contact Teacher'}
                </span>
              </div>
              <button
                onClick={() => setIsOpen(false)}
                className="text-gray-500 hover:text-gray-300 p-1 rounded-lg hover:bg-gray-700 transition"
              >
                <X className="w-4 h-4" />
              </button>
            </div>

            {/* Messages */}
            <div
              className="flex-1 overflow-y-auto p-3 space-y-3"
              style={{ minHeight: '200px', maxHeight: '400px' }}
            >
              {filteredMessages.length === 0 ? (
                <div className="flex flex-col items-center justify-center h-full text-gray-500 py-8">
                  <MessageSquare className="w-8 h-8 mb-2 opacity-50" />
                  <p className="text-xs font-medium">No messages yet</p>
                  <p className="text-xs text-gray-600 mt-1">
                    {isTeacher
                      ? 'Waiting for student messages...'
                      : 'Send a message to your teacher'}
                  </p>
                </div>
              ) : (
                filteredMessages.map(msg => {
                  const isFromMe = isTeacher
                    ? msg.type === 'teacher_reply' && msg.teacher_id === userId
                    : msg.type === 'student_message'
                  const isStudentMsg = msg.type === 'student_message'

                  return (
                    <div
                      key={msg.message_id}
                      className={`flex ${isFromMe ? 'justify-end' : 'justify-start'}`}
                    >
                      <div
                        className={`max-w-[80%] rounded-xl px-3 py-2 text-sm ${
                          isFromMe
                            ? 'bg-blue-600 text-white rounded-br-sm'
                            : isStudentMsg
                              ? 'bg-gray-800 text-gray-200 rounded-bl-sm border border-gray-700'
                              : 'bg-emerald-700/80 text-gray-100 rounded-bl-sm'
                        }`}
                      >
                        {!isFromMe && (
                          <p className="text-xs font-semibold mb-0.5 opacity-80">
                            {isStudentMsg
                              ? msg.student_name || 'Student'
                              : msg.teacher_name || 'Teacher'}
                          </p>
                        )}
                        <p className="whitespace-pre-wrap break-words">{msg.message}</p>
                        <p
                          className={`text-xs mt-1 ${isFromMe ? 'text-blue-200' : 'text-gray-500'}`}
                        >
                          {formatTime(msg.timestamp)}
                        </p>
                      </div>
                    </div>
                  )
                })
              )}
              <div ref={messagesEndRef} />
            </div>

            {/* Input */}
            <div className="border-t border-gray-700 p-3">
              <div className="flex items-center gap-2">
                <textarea
                  ref={inputRef}
                  value={input}
                  onChange={e => setInput(e.target.value)}
                  onKeyDown={e => {
                    if (e.key === 'Enter' && !e.shiftKey) {
                      e.preventDefault()
                      sendMessage()
                    }
                  }}
                  placeholder={isTeacher ? 'Type your reply...' : 'Type your message...'}
                  className="flex-1 bg-gray-800 border border-gray-700 rounded-xl px-3 py-2 text-sm text-gray-200 placeholder-gray-500 focus:outline-none focus:border-blue-500 resize-none"
                  rows={1}
                />
                <button
                  onClick={sendMessage}
                  disabled={!input.trim()}
                  className="p-2.5 bg-blue-600 text-white rounded-xl hover:bg-blue-700 transition disabled:opacity-50 disabled:cursor-not-allowed shrink-0"
                >
                  <Send className="w-4 h-4" />
                </button>
              </div>
              <p className="text-xs text-gray-600 mt-1">
                Press Enter to send, Shift+Enter for new line
              </p>
            </div>
          </motion.div>
        )}
      </AnimatePresence>
    </>
  )
}

import { useState, useEffect, useRef } from 'react'
import { createPortal } from 'react-dom'
import { X, AlertTriangle, Info, CheckCircle, AlertCircle } from 'lucide-react'

export type NotificationType = 'success' | 'error' | 'warning' | 'info' | 'violation'

export interface Notification {
  id: string
  type: NotificationType
  title: string
  message: string
  timestamp: number
  duration?: number
  action?: {
    label: string
    onClick: () => void
  }
}

interface NotificationContextValue {
  notifications: Notification[]
  addNotification: (notification: Omit<Notification, 'id' | 'timestamp'>) => void
  removeNotification: (id: string) => void
  clearAll: () => void
}

const NotificationContext = React.createContext<NotificationContextValue | null>(null)

export const useNotifications = () => {
  const context = React.useContext(NotificationContext)
  if (!context) {
    throw new Error('useNotifications must be used within NotificationProvider')
  }
  return context
}

export function NotificationProvider({ children }: { children: React.ReactNode }) {
  const [notifications, setNotifications] = useState<Notification[]>([])

  const addNotification = (notification: Omit<Notification, 'id' | 'timestamp'>) => {
    const newNotification: Notification = {
      ...notification,
      id: `notification-${Date.now()}-${Math.random()}`,
      timestamp: Date.now(),
      duration: notification.duration || 5000,
    }

    setNotifications(prev => [newNotification, ...prev])

    // Auto-remove after duration
    if (newNotification.duration && newNotification.duration > 0) {
      setTimeout(() => {
        removeNotification(newNotification.id)
      }, newNotification.duration)
    }

    // Play sound for violations
    if (notification.type === 'violation') {
      playNotificationSound('violation')
    } else if (notification.type === 'error') {
      playNotificationSound('error')
    }
  }

  const removeNotification = (id: string) => {
    setNotifications(prev => prev.filter(n => n.id !== id))
  }

  const clearAll = () => {
    setNotifications([])
  }

  const playNotificationSound = (type: 'violation' | 'error' | 'success') => {
    try {
      const audio = new Audio()
      if (type === 'violation') {
        audio.src =
          'data:audio/wav;base64,UklGRnoGAABXQVZFZm10IBAAAAABAAEAQB8AAEAfAAABAAgAZGF0YQoGAACBhYqFbF1fdJivrJBhNjVgodDbq2EcBj+a2/LDciUFLIHO8tiJNwgZaLvt559NEAxQp+PwtmMcBjiR1/LMeSwFJHfH8N2QQAoUXrTp66hVFApGn+DyvmwhBTGH0fPTgjMGHm7A7+OZTR' // Truncated for brevity
      }
      audio.volume = 0.3
      audio.play().catch(() => {}) // Ignore errors if autoplay blocked
    } catch (error) {
      console.error('Failed to play notification sound:', error)
    }
  }

  return (
    <NotificationContext.Provider
      value={{ notifications, addNotification, removeNotification, clearAll }}
    >
      {children}
      <NotificationContainer notifications={notifications} onRemove={removeNotification} />
    </NotificationContext.Provider>
  )
}

function NotificationContainer({
  notifications,
  onRemove,
}: {
  notifications: Notification[]
  onRemove: (id: string) => void
}) {
  return createPortal(
    <div className="fixed top-4 right-4 z-50 space-y-2 max-w-md">
      {notifications.map(notification => (
        <NotificationCard key={notification.id} notification={notification} onRemove={onRemove} />
      ))}
    </div>,
    document.body
  )
}

function NotificationCard({
  notification,
  onRemove,
}: {
  notification: Notification
  onRemove: (id: string) => void
}) {
  const [isExiting, setIsExiting] = useState(false)

  const handleRemove = () => {
    setIsExiting(true)
    setTimeout(() => onRemove(notification.id), 300)
  }

  const getIcon = () => {
    switch (notification.type) {
      case 'success':
        return <CheckCircle className="w-5 h-5 text-green-600" />
      case 'error':
        return <AlertCircle className="w-5 h-5 text-red-600" />
      case 'warning':
        return <AlertTriangle className="w-5 h-5 text-yellow-600" />
      case 'violation':
        return <AlertTriangle className="w-5 h-5 text-red-600 animate-pulse" />
      default:
        return <Info className="w-5 h-5 text-blue-600" />
    }
  }

  const getBgColor = () => {
    switch (notification.type) {
      case 'success':
        return 'bg-green-50 border-green-200'
      case 'error':
        return 'bg-red-50 border-red-200'
      case 'warning':
        return 'bg-yellow-50 border-yellow-200'
      case 'violation':
        return 'bg-red-100 border-red-300 shadow-lg shadow-red-200'
      default:
        return 'bg-blue-50 border-blue-200'
    }
  }

  return (
    <div
      className={`${getBgColor()} border rounded-lg p-4 shadow-lg backdrop-blur-sm transition-all duration-300 ${
        isExiting ? 'opacity-0 translate-x-full' : 'opacity-100 translate-x-0'
      }`}
    >
      <div className="flex items-start gap-3">
        {getIcon()}
        <div className="flex-1">
          <h4 className="font-semibold text-gray-900 text-sm">{notification.title}</h4>
          <p className="text-xs text-gray-700 mt-1">{notification.message}</p>
          {notification.action && (
            <button
              onClick={notification.action.onClick}
              className="mt-2 text-xs font-medium text-blue-600 hover:text-blue-700 underline"
            >
              {notification.action.label}
            </button>
          )}
        </div>
        <button onClick={handleRemove} className="text-gray-400 hover:text-gray-600 transition">
          <X className="w-4 h-4" />
        </button>
      </div>
    </div>
  )
}

// Violation notification hook with auto-subscribe to WebSocket
export function useViolationNotifications(examId?: string) {
  const { addNotification } = useNotifications()
  const wsRef = useRef<WebSocket | null>(null)

  useEffect(() => {
    if (!examId) return

    // Connect to WebSocket for real-time violation updates
    const wsUrl = `ws://localhost:8000/ws/violations/${examId}`
    const ws = new WebSocket(wsUrl)

    ws.onmessage = event => {
      try {
        const data = JSON.parse(event.data)
        if (data.type === 'violation') {
          addNotification({
            type: 'violation',
            title: `Violation Detected - ${data.student_name}`,
            message: data.violation_message,
            duration: 10000, // 10 seconds for violations
            action: {
              label: 'View Details',
              onClick: () => {
                // Navigate to student details or open modal
                console.log('View violation details:', data)
              },
            },
          })
        }
      } catch (error) {
        console.error('Failed to parse WebSocket message:', error)
      }
    }

    ws.onerror = error => {
      console.error('WebSocket error:', error)
    }

    wsRef.current = ws

    return () => {
      ws.close()
    }
  }, [examId, addNotification])
}

// Export React for the context
import React from 'react'

/**
 * AI-Powered Student Insights and Recommendations
 * Analyzes performance and provides personalized learning suggestions
 */

export interface PerformanceData {
  examId: string
  score: number
  totalQuestions: number
  correctAnswers: number
  timeSpent: number
  category: string
  difficulty: string
  answers: Array<{
    questionId: number
    isCorrect: boolean
    timeSpent: number
    difficulty: string
    topic: string
  }>
}

export interface StudentInsight {
  type: 'strength' | 'weakness' | 'improvement' | 'recommendation'
  category: string
  message: string
  confidence: number
  actionItems: string[]
  priority: 'high' | 'medium' | 'low'
}

export interface LearningRecommendation {
  title: string
  description: string
  topics: string[]
  estimatedTime: string
  difficulty: string
  resources: Array<{
    type: 'video' | 'article' | 'practice' | 'quiz'
    title: string
    url: string
  }>
}

class AIInsightsEngine {
  /**
   * Generate comprehensive insights from performance data
   */
  generateInsights(performanceHistory: PerformanceData[]): StudentInsight[] {
    const insights: StudentInsight[] = []

    if (performanceHistory.length === 0) {
      return insights
    }

    // Analyze strengths
    insights.push(...this.analyzeStrengths(performanceHistory))

    // Analyze weaknesses
    insights.push(...this.analyzeWeaknesses(performanceHistory))

    // Detect improvement trends
    insights.push(...this.analyzeImprovementTrends(performanceHistory))

    // Generate study recommendations
    insights.push(...this.generateStudyRecommendations(performanceHistory))

    // Sort by priority and confidence
    return insights.sort((a, b) => {
      const priorityOrder = { high: 3, medium: 2, low: 1 }
      if (priorityOrder[a.priority] !== priorityOrder[b.priority]) {
        return priorityOrder[b.priority] - priorityOrder[a.priority]
      }
      return b.confidence - a.confidence
    })
  }

  /**
   * Analyze student strengths
   */
  private analyzeStrengths(history: PerformanceData[]): StudentInsight[] {
    const insights: StudentInsight[] = []
    const categoryPerformance = this.calculateCategoryPerformance(history)

    // Find categories with >80% accuracy
    for (const [category, data] of Object.entries(categoryPerformance)) {
      if (data.accuracy > 0.8 && data.totalQuestions >= 5) {
        insights.push({
          type: 'strength',
          category,
          message: `You excel in ${category} with ${Math.round(data.accuracy * 100)}% accuracy!`,
          confidence: Math.min(data.accuracy, 1),
          actionItems: [
            `Consider mentoring others in ${category}`,
            `Challenge yourself with advanced ${category} topics`,
            `Maintain this strength with regular practice`,
          ],
          priority: 'low',
        })
      }
    }

    return insights
  }

  /**
   * Analyze student weaknesses
   */
  private analyzeWeaknesses(history: PerformanceData[]): StudentInsight[] {
    const insights: StudentInsight[] = []
    const categoryPerformance = this.calculateCategoryPerformance(history)
    const topicPerformance = this.calculateTopicPerformance(history)

    // Find categories with <60% accuracy
    for (const [category, data] of Object.entries(categoryPerformance)) {
      if (data.accuracy < 0.6 && data.totalQuestions >= 3) {
        const weakTopics = Object.entries(topicPerformance)
          .filter(([, perf]) => perf.category === category && perf.accuracy < 0.6)
          .map(([topic]) => topic)

        insights.push({
          type: 'weakness',
          category,
          message: `${category} needs improvement (${Math.round(data.accuracy * 100)}% accuracy)`,
          confidence: 1 - data.accuracy,
          actionItems: [
            `Review fundamentals of ${category}`,
            `Practice more ${category} questions`,
            weakTopics.length > 0
              ? `Focus on: ${weakTopics.slice(0, 3).join(', ')}`
              : 'Study core concepts',
            `Allocate 30-45 minutes daily for ${category}`,
          ],
          priority: data.accuracy < 0.5 ? 'high' : 'medium',
        })
      }
    }

    return insights
  }

  /**
   * Analyze improvement trends
   */
  private analyzeImprovementTrends(history: PerformanceData[]): StudentInsight[] {
    const insights: StudentInsight[] = []

    if (history.length < 3) return insights

    // Sort by time
    const sorted = [...history].sort(
      (a, b) => new Date(a.examId).getTime() - new Date(b.examId).getTime()
    )

    // Calculate improvement rate
    const recent = sorted.slice(-3)
    const older = sorted.slice(0, -3)

    if (older.length > 0) {
      const recentAvg =
        recent.reduce((sum, exam) => sum + exam.correctAnswers / exam.totalQuestions, 0) /
        recent.length
      const olderAvg =
        older.reduce((sum, exam) => sum + exam.correctAnswers / exam.totalQuestions, 0) /
        older.length

      const improvement = recentAvg - olderAvg

      if (improvement > 0.1) {
        insights.push({
          type: 'improvement',
          category: 'Overall Performance',
          message: `Great progress! Your scores improved by ${Math.round(improvement * 100)}%`,
          confidence: Math.min(improvement * 5, 1),
          actionItems: [
            'Keep up the excellent work!',
            'Your study strategy is working',
            'Consider increasing difficulty level',
          ],
          priority: 'medium',
        })
      } else if (improvement < -0.1) {
        insights.push({
          type: 'improvement',
          category: 'Overall Performance',
          message: `Scores declined by ${Math.round(Math.abs(improvement) * 100)}%. Let's get back on track!`,
          confidence: Math.min(Math.abs(improvement) * 5, 1),
          actionItems: [
            'Review recent study habits',
            'Ensure adequate rest before exams',
            'Focus on weak areas identified above',
            'Consider taking a short break to avoid burnout',
          ],
          priority: 'high',
        })
      }
    }

    return insights
  }

  /**
   * Generate personalized study recommendations
   */
  private generateStudyRecommendations(history: PerformanceData[]): StudentInsight[] {
    const insights: StudentInsight[] = []
    this.calculateCategoryPerformance(history)

    // Time management recommendation
    const avgTimePerQuestion =
      history.reduce((sum, exam) => sum + exam.timeSpent / exam.totalQuestions, 0) / history.length

    if (avgTimePerQuestion > 120) {
      // More than 2 minutes per question
      insights.push({
        type: 'recommendation',
        category: 'Time Management',
        message: 'You spend significant time per question. Speed practice recommended.',
        confidence: 0.8,
        actionItems: [
          'Practice timed mock exams',
          'Learn to eliminate wrong answers quickly',
          'Set time limits for each question',
          'Practice mental math for faster calculations',
        ],
        priority: 'medium',
      })
    }

    // Difficulty progression
    const difficultyDist = this.calculateDifficultyDistribution(history)
    if (difficultyDist.easy > 0.7 && difficultyDist.hard < 0.1) {
      insights.push({
        type: 'recommendation',
        category: 'Challenge Level',
        message: "You're ready for harder questions to accelerate growth",
        confidence: 0.85,
        actionItems: [
          'Attempt medium and hard difficulty questions',
          'Challenge yourself with advanced topics',
          'Join study groups for peer learning',
        ],
        priority: 'low',
      })
    }

    return insights
  }

  /**
   * Generate personalized learning path
   */
  generateLearningPath(
    insights: StudentInsight[],
    _performanceHistory: PerformanceData[]
  ): LearningRecommendation[] {
    const recommendations: LearningRecommendation[] = []

    // Get weak categories
    const weakCategories = insights
      .filter(i => i.type === 'weakness')
      .sort((a, b) => {
        const priorityOrder = { high: 3, medium: 2, low: 1 }
        return priorityOrder[b.priority] - priorityOrder[a.priority]
      })

    for (const weakness of weakCategories) {
      recommendations.push({
        title: `Master ${weakness.category}`,
        description: `Comprehensive study plan to improve your ${weakness.category} skills`,
        topics: weakness.actionItems
          .filter(item => item.includes('Focus on:'))
          .map(item => item.replace('Focus on: ', '')),
        estimatedTime: '2-3 weeks',
        difficulty: 'Beginner to Intermediate',
        resources: this.generateResources(weakness.category),
      })
    }

    return recommendations
  }

  /**
   * Calculate performance by category
   */
  private calculateCategoryPerformance(
    history: PerformanceData[]
  ): Record<string, { accuracy: number; totalQuestions: number }> {
    const categoryStats: Record<string, { correct: number; total: number }> = {}

    for (const exam of history) {
      if (!categoryStats[exam.category]) {
        categoryStats[exam.category] = { correct: 0, total: 0 }
      }
      categoryStats[exam.category].correct += exam.correctAnswers
      categoryStats[exam.category].total += exam.totalQuestions
    }

    const result: Record<string, { accuracy: number; totalQuestions: number }> = {}
    for (const [category, stats] of Object.entries(categoryStats)) {
      result[category] = {
        accuracy: stats.correct / stats.total,
        totalQuestions: stats.total,
      }
    }

    return result
  }

  /**
   * Calculate performance by topic
   */
  private calculateTopicPerformance(
    history: PerformanceData[]
  ): Record<string, { accuracy: number; category: string }> {
    const topicStats: Record<string, { correct: number; total: number; category: string }> = {}

    for (const exam of history) {
      for (const answer of exam.answers) {
        if (!topicStats[answer.topic]) {
          topicStats[answer.topic] = { correct: 0, total: 0, category: exam.category }
        }
        if (answer.isCorrect) {
          topicStats[answer.topic].correct++
        }
        topicStats[answer.topic].total++
      }
    }

    const result: Record<string, { accuracy: number; category: string }> = {}
    for (const [topic, stats] of Object.entries(topicStats)) {
      result[topic] = {
        accuracy: stats.correct / stats.total,
        category: stats.category,
      }
    }

    return result
  }

  /**
   * Calculate difficulty distribution
   */
  private calculateDifficultyDistribution(history: PerformanceData[]): Record<string, number> {
    const total = history.reduce((sum, exam) => sum + exam.totalQuestions, 0)
    const distribution: Record<string, number> = { easy: 0, medium: 0, hard: 0 }

    for (const exam of history) {
      for (const answer of exam.answers) {
        const difficulty = answer.difficulty.toLowerCase()
        distribution[difficulty] = (distribution[difficulty] || 0) + 1
      }
    }

    return {
      easy: distribution.easy / total,
      medium: distribution.medium / total,
      hard: distribution.hard / total,
    }
  }

  /**
   * Generate learning resources
   */
  private generateResources(
    category: string
  ): Array<{ type: 'video' | 'article' | 'practice' | 'quiz'; title: string; url: string }> {
    // This would normally fetch from a database or API
    return [
      {
        type: 'video',
        title: `${category} Fundamentals - Complete Course`,
        url: `/resources/videos/${category.toLowerCase()}-fundamentals`,
      },
      {
        type: 'article',
        title: `Understanding ${category} - Study Guide`,
        url: `/resources/guides/${category.toLowerCase()}`,
      },
      {
        type: 'practice',
        title: `${category} Practice Questions (100+)`,
        url: `/practice/${category.toLowerCase()}`,
      },
      {
        type: 'quiz',
        title: `${category} Quick Assessment`,
        url: `/quiz/${category.toLowerCase()}`,
      },
    ]
  }

  /**
   * Calculate optimal study schedule
   */
  calculateStudySchedule(
    insights: StudentInsight[],
    availableHoursPerWeek: number
  ): Array<{
    day: string
    topic: string
    duration: number
    priority: string
  }> {
    const schedule: Array<{ day: string; topic: string; duration: number; priority: string }> = []
    const days = ['Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday', 'Saturday', 'Sunday']

    // Sort topics by priority
    const topics = insights
      .filter(i => i.type === 'weakness' || i.type === 'recommendation')
      .sort((a, b) => {
        const priorityOrder = { high: 3, medium: 2, low: 1 }
        return priorityOrder[b.priority] - priorityOrder[a.priority]
      })

    const hoursPerDay = availableHoursPerWeek / 7
    let dayIndex = 0

    for (const topic of topics) {
      const hours = topic.priority === 'high' ? 2 : topic.priority === 'medium' ? 1.5 : 1

      schedule.push({
        day: days[dayIndex % 7],
        topic: topic.category,
        duration: Math.min(hours, hoursPerDay),
        priority: topic.priority,
      })

      dayIndex++
    }

    return schedule
  }
}

