/**
 * Performance Monitoring and Analytics
 * Tracks Core Web Vitals and user experience metrics
 */

interface PerformanceMetric {
  name: string
  value: number
  rating: 'good' | 'needs-improvement' | 'poor'
  timestamp: number
}

interface UserInteraction {
  type: 'click' | 'scroll' | 'navigation' | 'input'
  target?: string
  timestamp: number
  duration?: number
}

class PerformanceMonitor {
  private metrics: PerformanceMetric[] = []
  private interactions: UserInteraction[] = []
  private observer: PerformanceObserver | null = null
  private fpsHistory: number[] = []
  private lastFrameTime = 0
  private maxMetrics = 100 // Limit stored metrics to prevent memory leaks

  /**
   * Initialize performance monitoring
   */
  init() {
    // Monitor Core Web Vitals
    this.observeCoreWebVitals()

    // Monitor user interactions
    this.trackInteractions()

    // Monitor resource loading
    this.observeResourceTiming()

    // Monitor FPS
    this.trackFPS()

    // Disabled: Verbose initialization log
    // console.log('Γ£à Performance monitoring initialized')
  }

  /**
   * Track FPS for smooth experience monitoring
   */
  private trackFPS() {
    const measureFPS = (timestamp: number) => {
      if (this.lastFrameTime) {
        const fps = 1000 / (timestamp - this.lastFrameTime)
        this.fpsHistory.push(fps)

        // Keep only last 60 frames
        if (this.fpsHistory.length > 60) {
          this.fpsHistory.shift()
        }

        // Disabled: FPS logging (too verbose)
        // if (fps < 10 && fps > 0) {
        //   console.warn('ΓÜá∩╕Å Critical FPS drop:', fps.toFixed(1))
        // }
      }
      this.lastFrameTime = timestamp
      requestAnimationFrame(measureFPS)
    }

    requestAnimationFrame(measureFPS)
  }

  /**
   * Get average FPS
   */
  getAverageFPS(): number {
    if (this.fpsHistory.length === 0) return 60
    return this.fpsHistory.reduce((a, b) => a + b, 0) / this.fpsHistory.length
  }

  /**
   * Observe Core Web Vitals (LCP, FID, CLS)
   */
  private observeCoreWebVitals() {
    // Largest Contentful Paint (LCP)
    this.observeMetric('largest-contentful-paint', (entry: any) => {
      const value = entry.renderTime || entry.loadTime
      this.recordMetric('LCP', value, this.getLCPRating(value))
    })

    // First Input Delay (FID)
    this.observeMetric('first-input', (entry: any) => {
      const value = entry.processingStart - entry.startTime
      this.recordMetric('FID', value, this.getFIDRating(value))
    })

    // Cumulative Layout Shift (CLS)
    this.observeMetric('layout-shift', (entry: any) => {
      if (!entry.hadRecentInput) {
        const value = entry.value
        this.recordMetric('CLS', value, this.getCLSRating(value))
      }
    })

    // Time to First Byte (TTFB)
    if (window.performance && window.performance.timing) {
      const ttfb = window.performance.timing.responseStart - window.performance.timing.requestStart
      this.recordMetric('TTFB', ttfb, this.getTTFBRating(ttfb))
    }
  }

  /**
   * Observe specific performance entry type
   */
  private observeMetric(type: string, callback: (entry: any) => void) {
    try {
      const observer = new PerformanceObserver(list => {
        for (const entry of list.getEntries()) {
          callback(entry)
        }
      })
      observer.observe({ type, buffered: true })
    } catch (error) {
      console.warn(`Could not observe ${type}:`, error)
    }
  }

  /**
   * Track user interactions
   */
  private trackInteractions() {
    // Track clicks
    document.addEventListener('click', e => {
      const target = e.target as HTMLElement
      this.interactions.push({
        type: 'click',
        target: target.tagName + (target.id ? `#${target.id}` : ''),
        timestamp: Date.now(),
      })
    })

    // Track scrolling
    let scrollTimeout: number
    document.addEventListener('scroll', () => {
      clearTimeout(scrollTimeout)
      scrollTimeout = window.setTimeout(() => {
        this.interactions.push({
          type: 'scroll',
          timestamp: Date.now(),
        })
      }, 100)
    })
  }

  /**
   * Observe resource loading times
   */
  private observeResourceTiming() {
    this.observeMetric('resource', (entry: PerformanceResourceTiming) => {
      // Disabled: Slow resource warnings (too verbose for development)
      // Only enable if debugging performance issues
      // if (duration > 10000) {
      //   console.warn(`Extremely slow resource: ${entry.name} (${duration.toFixed(0)}ms)`)
      // }
    })
  }

  /**
   * Record a metric
   */
  private recordMetric(name: string, value: number, rating: 'good' | 'needs-improvement' | 'poor') {
    const metric: PerformanceMetric = {
      name,
      value,
      rating,
      timestamp: Date.now(),
    }

    this.metrics.push(metric)

    // Disabled: Metric logging (too verbose)
    // Uncomment only when debugging performance issues
    // if (rating === 'poor' && value > 0.5) {
    //   console.warn(`Γ¥î Critical ${name}: ${value.toFixed(2)}`)
    // }
  }

  /**
   * Rating functions based on Web Vitals thresholds
   */
  private getLCPRating(value: number): 'good' | 'needs-improvement' | 'poor' {
    if (value <= 2500) return 'good'
    if (value <= 4000) return 'needs-improvement'
    return 'poor'
  }

  private getFIDRating(value: number): 'good' | 'needs-improvement' | 'poor' {
    if (value <= 100) return 'good'
    if (value <= 300) return 'needs-improvement'
    return 'poor'
  }

  private getCLSRating(value: number): 'good' | 'needs-improvement' | 'poor' {
    if (value <= 0.1) return 'good'
    if (value <= 0.25) return 'needs-improvement'
    return 'poor'
  }

  private getTTFBRating(value: number): 'good' | 'needs-improvement' | 'poor' {
    if (value <= 800) return 'good'
    if (value <= 1800) return 'needs-improvement'
    return 'poor'
  }

  /**
   * Get performance summary
   */
  getSummary() {
    const summary: Record<string, any> = {}

    this.metrics.forEach(metric => {
      if (!summary[metric.name] || summary[metric.name].timestamp < metric.timestamp) {
        summary[metric.name] = metric
      }
    })

    return summary
  }

  /**
   * Get interaction analytics
   */
  getInteractionAnalytics() {
    const clickCount = this.interactions.filter(i => i.type === 'click').length
    const scrollCount = this.interactions.filter(i => i.type === 'scroll').length

    return {
      totalInteractions: this.interactions.length,
      clicks: clickCount,
      scrolls: scrollCount,
      engagementScore: Math.min(100, (clickCount + scrollCount) * 2),
    }
  }

  /**
   * Measure specific operation
   */
  async measureOperation<T>(name: string, operation: () => Promise<T>): Promise<T> {
    const start = performance.now()
    try {
      const result = await operation()
      const duration = performance.now() - start

      // Disabled: Operation timing logs (too verbose)
      // console.log(`ΓÅ▒∩╕Å ${name}: ${duration.toFixed(2)}ms`)

      // Record if slow (>100ms)
      if (duration > 100) {
        this.recordMetric(name, duration, duration > 500 ? 'poor' : 'needs-improvement')
      }

      return result
    } catch (error) {
      // Disabled: Only log critical async errors in production
      // console.error(`Γ¥î ${name} failed after ${duration.toFixed(2)}ms:`, error)
      throw error
    }
  }

  /**
   * Get memory usage (if available)
   */
  getMemoryUsage() {
    if ('memory' in performance) {
      const memory = (performance as any).memory
      return {
        usedJSHeapSize: memory.usedJSHeapSize,
        totalJSHeapSize: memory.totalJSHeapSize,
        jsHeapSizeLimit: memory.jsHeapSizeLimit,
        percentUsed: ((memory.usedJSHeapSize / memory.jsHeapSizeLimit) * 100).toFixed(2),
      }
    }
    return null
  }

  /**
   * Export metrics for analytics
   */
  exportMetrics() {
    return {
      vitals: this.getSummary(),
      interactions: this.getInteractionAnalytics(),
      memory: this.getMemoryUsage(),
      timestamp: Date.now(),
    }
  }

  /**
   * Clear old metrics (keep last 100)
   */
  cleanup() {
    if (this.metrics.length > 100) {
      this.metrics = this.metrics.slice(-100)
    }
    if (this.interactions.length > 100) {
      this.interactions = this.interactions.slice(-100)
    }
  }
}

export const performanceMonitor = new PerformanceMonitor()

/**
 * Responsive Utilities for Multi-Device Support
 * Ensures seamless experience across all screen sizes
 */

export enum ScreenSize {
  MOBILE = 'mobile',
  TABLET = 'tablet',
  DESKTOP = 'desktop',
  LARGE = 'large',
}

export enum Orientation {
  PORTRAIT = 'portrait',
  LANDSCAPE = 'landscape',
}

export interface DeviceInfo {
  screenSize: ScreenSize
  width: number
  height: number
  orientation: Orientation
  isTouchDevice: boolean
  isRetina: boolean
  devicePixelRatio: number
}

/**
 * Breakpoints matching Tailwind config
 */
export const BREAKPOINTS = {
  sm: 640,
  md: 768,
  lg: 1024,
  xl: 1280,
  '2xl': 1536,
} as const

/**
 * Get current screen size category
 */
export const getScreenSize = (width: number): ScreenSize => {
  if (width < BREAKPOINTS.md) return ScreenSize.MOBILE
  if (width < BREAKPOINTS.lg) return ScreenSize.TABLET
  if (width < BREAKPOINTS['2xl']) return ScreenSize.DESKTOP
  return ScreenSize.LARGE
}

/**
 * Get current orientation
 */
export const getOrientation = (): Orientation => {
  return window.innerWidth > window.innerHeight ? Orientation.LANDSCAPE : Orientation.PORTRAIT
}

/**
 * Check if device has touch capability
 */
export const isTouchDevice = (): boolean => {
  return (
    'ontouchstart' in window ||
    navigator.maxTouchPoints > 0 ||
    // @ts-expect-error - Legacy support
    navigator.msMaxTouchPoints > 0
  )
}

/**
 * Check if device has retina display
 */
export const isRetinaDisplay = (): boolean => {
  return window.devicePixelRatio > 1
}

/**
 * Get comprehensive device information
 */
export const getDeviceInfo = (): DeviceInfo => {
  const width = window.innerWidth
  const height = window.innerHeight

  return {
    screenSize: getScreenSize(width),
    width,
    height,
    orientation: getOrientation(),
    isTouchDevice: isTouchDevice(),
    isRetina: isRetinaDisplay(),
    devicePixelRatio: window.devicePixelRatio || 1,
  }
}

/**
 * Media query matchers for reactive components
 */
export const mediaQueries = {
  mobile: `(max-width: ${BREAKPOINTS.md - 1}px)`,
  tablet: `(min-width: ${BREAKPOINTS.md}px) and (max-width: ${BREAKPOINTS.lg - 1}px)`,
  desktop: `(min-width: ${BREAKPOINTS.lg}px)`,
  large: `(min-width: ${BREAKPOINTS['2xl']}px)`,
  portrait: '(orientation: portrait)',
  landscape: '(orientation: landscape)',
  touch: '(hover: none) and (pointer: coarse)',
  retina: '(-webkit-min-device-pixel-ratio: 2), (min-resolution: 192dpi)',
}

/**
 * Check if media query matches
 */
export const matchesMediaQuery = (query: string): boolean => {
  return window.matchMedia(query).matches
}

/**
 * Get optimal font size based on screen size
 */
export const getOptimalFontSize = (baseSize: number = 16): number => {
  const { screenSize } = getDeviceInfo()

  const multipliers = {
    [ScreenSize.MOBILE]: 0.875, // 14px
    [ScreenSize.TABLET]: 0.9375, // 15px
    [ScreenSize.DESKTOP]: 1, // 16px
    [ScreenSize.LARGE]: 1.125, // 18px
  }

  return baseSize * multipliers[screenSize]
}

/**
 * Get optimal spacing based on screen size
 */
export const getOptimalSpacing = (baseSpacing: number = 16): number => {
  const { screenSize } = getDeviceInfo()

  const multipliers = {
    [ScreenSize.MOBILE]: 0.75, // 12px
    [ScreenSize.TABLET]: 0.875, // 14px
    [ScreenSize.DESKTOP]: 1, // 16px
    [ScreenSize.LARGE]: 1.25, // 20px
  }

  return baseSpacing * multipliers[screenSize]
}

/**
 * Get optimal image quality based on screen
 */
export const getOptimalImageQuality = (): 'low' | 'medium' | 'high' => {
  const { screenSize, isRetina } = getDeviceInfo()

  if (screenSize === ScreenSize.MOBILE && !isRetina) return 'low'
  if (screenSize === ScreenSize.TABLET || (screenSize === ScreenSize.MOBILE && isRetina))
    return 'medium'
  return 'high'
}

/**
 * Get column count for grid layouts
 */
export const getGridColumns = (
  options: {
    mobile?: number
    tablet?: number
    desktop?: number
    large?: number
  } = {}
): number => {
  const { screenSize } = getDeviceInfo()

  const defaults = {
    mobile: 1,
    tablet: 2,
    desktop: 3,
    large: 4,
  }

  const columns = { ...defaults, ...options }

  switch (screenSize) {
    case ScreenSize.MOBILE:
      return columns.mobile
    case ScreenSize.TABLET:
      return columns.tablet
    case ScreenSize.DESKTOP:
      return columns.desktop
    case ScreenSize.LARGE:
      return columns.large
    default:
      return columns.desktop
  }
}

/**
 * Format bytes for display based on locale
 */
export const formatBytes = (bytes: number, decimals: number = 2): string => {
  if (bytes === 0) return '0 Bytes'

  const k = 1024
  const dm = decimals < 0 ? 0 : decimals
  const sizes = ['Bytes', 'KB', 'MB', 'GB', 'TB']
  const i = Math.floor(Math.log(bytes) / Math.log(k))

  return parseFloat((bytes / Math.pow(k, i)).toFixed(dm)) + ' ' + sizes[i]
}

/**
 * Get safe area insets for notched devices
 */
export const getSafeAreaInsets = () => {
  const style = getComputedStyle(document.documentElement)

  return {
    top: parseInt(style.getPropertyValue('--safe-area-inset-top') || '0'),
    right: parseInt(style.getPropertyValue('--safe-area-inset-right') || '0'),
    bottom: parseInt(style.getPropertyValue('--safe-area-inset-bottom') || '0'),
    left: parseInt(style.getPropertyValue('--safe-area-inset-left') || '0'),
  }
}

/**
 * Lock screen orientation (mobile only)
 */
export const lockOrientation = async (
  orientation: 'portrait' | 'landscape' | 'portrait-primary' | 'landscape-primary'
): Promise<boolean> => {
  if (!('orientation' in screen)) return false

  try {
    // @ts-expect-error - Screen Orientation API
    await screen.orientation.lock(orientation)
    return true
  } catch (error) {
    console.warn('Orientation lock not supported:', error)
    return false
  }
}

/**
 * Unlock screen orientation
 */
export const unlockOrientation = (): void => {
  if ('orientation' in screen) {
    // @ts-expect-error - Screen Orientation API
    screen.orientation.unlock()
  }
}

/**
 * Check if device is in fullscreen mode
 */
export const isFullscreen = (): boolean => {
  return !!(
    document.fullscreenElement ||
    // @ts-expect-error - Vendor prefixes
    document.webkitFullscreenElement ||
    // @ts-expect-error
    document.mozFullScreenElement ||
    // @ts-expect-error
    document.msFullscreenElement
  )
}

/**
 * Request fullscreen on element
 */
export const requestFullscreen = async (
  element: HTMLElement = document.documentElement
): Promise<boolean> => {
  try {
    if (element.requestFullscreen) {
      await element.requestFullscreen()
    } else if ((element as any).webkitRequestFullscreen) {
      await (element as any).webkitRequestFullscreen()
    } else if ((element as any).mozRequestFullScreen) {
      await (element as any).mozRequestFullScreen()
    } else if ((element as any).msRequestFullscreen) {
      await (element as any).msRequestFullscreen()
    }
    return true
  } catch (error) {
    console.warn('Fullscreen request failed:', error)
    return false
  }
}

/**
 * Exit fullscreen mode
 */
export const exitFullscreen = async (): Promise<boolean> => {
  try {
    if (document.exitFullscreen) {
      await document.exitFullscreen()
    } else if ((document as any).webkitExitFullscreen) {
      await (document as any).webkitExitFullscreen()
    } else if ((document as any).mozCancelFullScreen) {
      await (document as any).mozCancelFullScreen()
    } else if ((document as any).msExitFullscreen) {
      await (document as any).msExitFullscreen()
    }
    return true
  } catch (error) {
    console.warn('Exit fullscreen failed:', error)
    return false
  }
}

/**
 * Vibrate device (mobile only)
 */
export const vibrate = (pattern: number | number[]): boolean => {
  if (!('vibrate' in navigator)) return false

  try {
    navigator.vibrate(pattern)
    return true
  } catch (error) {
    console.warn('Vibration not supported:', error)
    return false
  }
}

/**
 * Show notification (requires permission)
 */
export const showNotification = async (
  title: string,
  options?: NotificationOptions
): Promise<boolean> => {
  if (!('Notification' in window)) return false

  if (Notification.permission === 'granted') {
    new Notification(title, options)
    return true
  }

  if (Notification.permission !== 'denied') {
    const permission = await Notification.requestPermission()
    if (permission === 'granted') {
      new Notification(title, options)
      return true
    }
  }

  return false
}

/**
 * Copy text to clipboard
 */
export const copyToClipboard = async (text: string): Promise<boolean> => {
  try {
    if (navigator.clipboard && navigator.clipboard.writeText) {
      await navigator.clipboard.writeText(text)
      return true
    }

    // Fallback for older browsers
    const textarea = document.createElement('textarea')
    textarea.value = text
    textarea.style.position = 'fixed'
    textarea.style.opacity = '0'
    document.body.appendChild(textarea)
    textarea.select()
    const success = document.execCommand('copy')
    document.body.removeChild(textarea)
    return success
  } catch (error) {
    console.warn('Clipboard copy failed:', error)
    return false
  }
}

/**
 * Share content using Web Share API (mobile)
 */
export const shareContent = async (data: ShareData): Promise<boolean> => {
  if (!('share' in navigator)) return false

  try {
    await navigator.share(data)
    return true
  } catch (error) {
    console.warn('Share failed:', error)
    return false
  }
}

/**
 * Check if device has camera
 */
export const hasCamera = async (): Promise<boolean> => {
  try {
    const devices = await navigator.mediaDevices.enumerateDevices()
    return devices.some(device => device.kind === 'videoinput')
  } catch (error) {
    return false
  }
}

/**
 * Check if device has microphone
 */
export const hasMicrophone = async (): Promise<boolean> => {
  try {
    const devices = await navigator.mediaDevices.enumerateDevices()
    return devices.some(device => device.kind === 'audioinput')
  } catch (error) {
    return false
  }
}

/**
 * Get network information
 */
export const getNetworkInfo = () => {
  // @ts-expect-error - Experimental API
  const connection = navigator.connection || navigator.mozConnection || navigator.webkitConnection

  if (!connection) {
    return {
      effectiveType: 'unknown',
      downlink: undefined,
      rtt: undefined,
      saveData: false,
    }
  }

  return {
    effectiveType: connection.effectiveType || 'unknown', // 4g, 3g, 2g, slow-2g
    downlink: connection.downlink, // Mbps
    rtt: connection.rtt, // Round trip time in ms
    saveData: connection.saveData || false,
  }
}

/**
 * Check if device is online
 */
export const isOnline = (): boolean => {
  return navigator.onLine
}

/**
 * Get battery status (if available)
 */
export const getBatteryStatus = async () => {
  // @ts-expect-error - Experimental Network Information API
  if (!('getBattery' in navigator)) {
    return null
  }

  try {
    // @ts-expect-error
    const battery = await navigator.getBattery()
    return {
      level: battery.level * 100, // 0-100%
      charging: battery.charging,
      chargingTime: battery.chargingTime, // seconds
      dischargingTime: battery.dischargingTime, // seconds
    }
  } catch (error) {
    return null
  }
}

/**
 * Prevent screen sleep (during exams)
 */
export const preventScreenSleep = async (): Promise<WakeLockSentinel | null> => {
  // @ts-expect-error - Experimental Wake Lock API check
  if (!('wakeLock' in navigator)) {
    console.warn('Wake Lock API not supported')
    return null
  }

  try {
    // @ts-expect-error - Experimental Wake Lock API request
    const wakeLock = await navigator.wakeLock.request('screen')
    console.log('Screen wake lock activated')
    return wakeLock
  } catch (error) {
    console.warn('Wake Lock request failed:', error)
    return null
  }
}

