  /**
   * Disconnect from WebSocket server
   */
  disconnect() {
    this.isIntentionallyClosed = true
    this.stopHeartbeat()
    
    if (this.ws) {
      this.ws.close()
      this.ws = null
    }
    
    logger.info('WebSocket disconnected')
  }

  /**
   * Send message to server
   */
  send(type: string, payload: any) {
    if (!this.isConnected()) {
      logger.warn('Cannot send message - WebSocket not connected')
      return false
    }

    try {
      const message: WebSocketMessage = {
        type,
        payload,
        timestamp: Date.now()
      }

      this.ws!.send(JSON.stringify(message))
      logger.debug('WebSocket message sent', { type, payload })
      return true
    } catch (error) {
      logger.error('Failed to send WebSocket message', error)
      return false
    }
  }

  /**
   * Subscribe to message type
   */
  subscribe(type: string, handler: MessageHandler) {
    if (!this.messageHandlers.has(type)) {
      this.messageHandlers.set(type, new Set())
    }
    
    this.messageHandlers.get(type)!.add(handler)
    
    logger.debug('Subscribed to WebSocket messages', { type })
    
    // Return unsubscribe function
    return () => this.unsubscribe(type, handler)
  }

  /**
   * Unsubscribe from message type
   */
  unsubscribe(type: string, handler: MessageHandler) {
    const handlers = this.messageHandlers.get(type)
    if (handlers) {
      handlers.delete(handler)
      
      if (handlers.size === 0) {
        this.messageHandlers.delete(type)
      }
    }
  }

  /**
   * Check if connected
   */
  isConnected(): boolean {
    return this.ws?.readyState === WebSocket.OPEN
  }

  /**
   * Handle connection open
   */
  private handleOpen() {
    logger.info('WebSocket connected')
    this.reconnectAttempts = 0
    this.startHeartbeat()
    
    toast.success('Real-time connection established')
    
    // Notify subscribers
    this.notifyHandlers('connection', { status: 'connected' })
  }

  /**
   * Handle incoming message
   */
  private handleMessage(event: MessageEvent) {
    try {
      const message: WebSocketMessage = JSON.parse(event.data)
      
      logger.debug('WebSocket message received', { type: message.type })
      
      // Notify subscribed handlers
      this.notifyHandlers(message.type, message.payload)
      
      // Handle specific message types
      this.handleSpecialMessages(message)
    } catch (error) {
      logger.error('Failed to parse WebSocket message', error)
    }
  }

  /**
   * Handle WebSocket error
   */
  private handleError(event: Event) {
    logger.error('WebSocket error', event)
  }

  /**
   * Handle connection close
   */
  private handleClose(event: CloseEvent) {
    logger.warn('WebSocket closed', {
      code: event.code,
      reason: event.reason,
      wasClean: event.wasClean
    })
    
    this.stopHeartbeat()
    
    if (!this.isIntentionallyClosed) {
      toast.error('Connection lost. Reconnecting...')
      this.scheduleReconnect()
    }
    
    // Notify subscribers
    this.notifyHandlers('connection', { status: 'disconnected' })
  }

  /**
   * Schedule reconnection attempt
   */
  private scheduleReconnect() {
    if (this.reconnectAttempts >= this.maxReconnectAttempts) {
      logger.error('Max reconnect attempts reached')
      toast.error('Unable to establish connection. Please refresh the page.')
      return
    }

    this.reconnectAttempts++
    const delay = this.reconnectDelay * Math.pow(2, this.reconnectAttempts - 1)
    
    logger.info(`Reconnecting in ${delay}ms (attempt ${this.reconnectAttempts}/${this.maxReconnectAttempts})`)
    
    setTimeout(() => {
      this.connect()
    }, delay)
  }

  /**
   * Start heartbeat to keep connection alive
   */
  private startHeartbeat() {
    this.stopHeartbeat()
    
    this.heartbeatInterval = setInterval(() => {
      if (this.isConnected()) {
        this.send('ping', { timestamp: Date.now() })
      }
    }, 30000) // Every 30 seconds
  }

  /**
   * Stop heartbeat
   */
  private stopHeartbeat() {
    if (this.heartbeatInterval) {
      clearInterval(this.heartbeatInterval)
      this.heartbeatInterval = null
    }
  }

  /**
   * Notify all handlers for a message type
   */
  private notifyHandlers(type: string, payload: any) {
    const handlers = this.messageHandlers.get(type)
    if (handlers) {
      handlers.forEach(handler => {
        try {
          handler(payload)
        } catch (error) {
          logger.error('Message handler error', { type, error })
        }
      })
    }
  }

  /**
   * Handle special system messages
   */
  private handleSpecialMessages(message: WebSocketMessage) {
    switch (message.type) {
      case 'notification':
        toast.info(message.payload.message, {
          description: message.payload.description
        })
        break
        
      case 'violation_alert':
        toast.warning('Proctoring Alert', {
          description: message.payload.message
        })
        break
        
      case 'exam_ended':
        toast.error('Exam Ended', {
          description: message.payload.reason
        })
        break
        
      case 'pong':
        logger.debug('Heartbeat response received')
        break
    }
  }
}

// Create singleton instance
export const wsManager = new WebSocketManager()

// Expose in development
if (import.meta.env.DEV) {
  (window as any).wsManager = wsManager
}

/**
 * React hook for WebSocket subscriptions
 */
import { useEffect } from 'react'

export function useWebSocket(type: string, handler: MessageHandler, deps: any[] = []) {
  useEffect(() => {
    const unsubscribe = wsManager.subscribe(type, handler)
    return unsubscribe
  }, [type, ...deps])
}

export default wsManager

import { useState, useEffect } from 'react'
import { useAuthStore } from '../store/globalStore'
import { notificationsAPI } from '../lib/api'
import { toast } from 'sonner'
import {
  Bell,
  CheckCircle,
  AlertTriangle,
  Calendar,
  Trophy,
  X,
  Filter,
  Settings,
  MessageSquare,
  Clock,
  Trash2,
  Eye,
  Send,
} from 'lucide-react'

interface Notification {
  _id: string
  type:
    | 'exam'
    | 'grade'
    | 'security'
    | 'announcement'
    | 'achievement'
    | 'reminder'
    | 'info'
    | 'success'
    | 'warning'
    | 'error'
  title: string
  message: string
  priority: 'low' | 'normal' | 'medium' | 'high' | 'urgent'
  read: boolean
  timestamp?: Date
  created_at?: string
  action_url?: string
  actionUrl?: string
  actionText?: string
  metadata?: any
}

export default function NotificationCenterPage() {
  const { user } = useAuthStore()
  const [notifications, setNotifications] = useState<Notification[]>([])
  const [filteredNotifications, setFilteredNotifications] = useState<Notification[]>([])
  const [filter, setFilter] = useState<'all' | 'unread' | 'exam' | 'grade' | 'security'>('all')
  const [loading, setLoading] = useState(true)
  const [stats, setStats] = useState({
    total: 0,
    unread: 0,
    today: 0,
    exams: 0,
    grades: 0,
    security: 0,
  })
  const [showCreateModal, setShowCreateModal] = useState(false)
  const [newNotification, setNewNotification] = useState({
    type: 'announcement',
    title: '',
    message: '',
    priority: 'medium',
    targetRole: 'all',
    targetUsers: [],
  })

  useEffect(() => {
    loadNotifications()
    loadStats()

    // Auto-refresh every 30 seconds
    const interval = setInterval(() => {
      loadNotifications(true)
    }, 30000)

    return () => clearInterval(interval)
  }, [])

  useEffect(() => {
    filterNotifications()
  }, [filter, notifications])

  const loadNotifications = async (silent = false) => {
    try {
      if (!silent) setLoading(true)
      const data = await notificationsAPI.getNotifications(false, 100)

      // Transform backend format to frontend format
      const transformedNotifications = data.map((n: any) => ({
        ...n,
        timestamp: new Date(n.created_at),
        actionUrl: n.action_url,
      }))

      setNotifications(transformedNotifications)
      setFilteredNotifications(transformedNotifications)
    } catch (error) {
      console.error('Failed to load notifications:', error)
      toast.error('Failed to load notifications')
    } finally {
      if (!silent) setLoading(false)
    }
  }

  const loadStats = async () => {
    try {
      const data = await notificationsAPI.getStats()
      setStats(data)
    } catch (error) {
      console.error('Failed to load notification stats:', error)
    }
  }

  const filterNotifications = () => {
    let filtered = [...notifications]

    if (filter === 'unread') {
      filtered = filtered.filter(n => !n.read)
    } else if (filter !== 'all') {
      filtered = filtered.filter(n => n.type === filter)
    }

    setFilteredNotifications(filtered)
  }

  const markAsRead = async (id: string) => {
    try {
      await notificationsAPI.markAsRead([id])
      setNotifications(notifications.map(n => (n._id === id ? { ...n, read: true } : n)))
      setStats(prev => ({ ...prev, unread: Math.max(0, prev.unread - 1) }))
    } catch (error) {
      toast.error('Failed to mark as read')
    }
  }

  const markAllAsRead = async () => {
    try {
      await notificationsAPI.markAllAsRead()
      setNotifications(notifications.map(n => ({ ...n, read: true })))
      setStats(prev => ({ ...prev, unread: 0 }))
      toast.success('All notifications marked as read')
    } catch (error) {
      toast.error('Failed to mark all as read')
    }
  }

  const deleteNotification = async (id: string) => {
    try {
      await notificationsAPI.deleteNotification(id)
      setNotifications(notifications.filter(n => n._id !== id))
      setStats(prev => ({
        ...prev,
        total: Math.max(0, prev.total - 1),
        unread: prev.unread - (notifications.find(n => n._id === id)?.read ? 0 : 1),
      }))
      toast.success('Notification deleted')
    } catch (error) {
      toast.error('Failed to delete notification')
    }
  }

  const getNotificationIcon = (type: string) => {
    switch (type) {
      case 'exam':
        return <Calendar className="w-5 h-5" />
      case 'violation':
        return <AlertTriangle className="w-5 h-5" />
      case 'system':
        return <Settings className="w-5 h-5" />
      case 'message':
        return <MessageSquare className="w-5 h-5" />
      default:
        return <Bell className="w-5 h-5" />
    }
  }

  const formatDate = (date: Date | string) => {
    const dateObj = typeof date === 'string' ? new Date(date) : date
    const seconds = Math.floor((Date.now() - dateObj.getTime()) / 1000)

    if (seconds < 60) return 'Just now'
    if (seconds < 3600) return `${Math.floor(seconds / 60)} minutes ago`
    if (seconds < 86400) return `${Math.floor(seconds / 3600)} hours ago`
    if (seconds < 604800) return `${Math.floor(seconds / 86400)} days ago`
    return dateObj.toLocaleDateString()
  }

  const getNotificationColor = (type: string, priority: string) => {
    if (priority === 'high') return 'bg-red-100 text-red-600 border-red-200'

    switch (type) {
      case 'exam':
        return 'bg-blue-100 text-blue-600 border-blue-200'
      case 'grade':
        return 'bg-green-100 text-green-600 border-green-200'
      case 'security':
        return 'bg-orange-100 text-orange-600 border-orange-200'
      case 'announcement':
        return 'bg-purple-100 text-purple-600 border-purple-200'
      case 'achievement':
        return 'bg-yellow-100 text-yellow-600 border-yellow-200'
      case 'reminder':
        return 'bg-cyan-100 text-cyan-600 border-cyan-200'
      default:
        return 'bg-gray-100 text-gray-600 border-gray-200'
    }
  }

  const getTimeAgo = (date: Date) => {
    const seconds = Math.floor((Date.now() - date.getTime()) / 1000)

    if (seconds < 60) return 'Just now'
    if (seconds < 3600) return `${Math.floor(seconds / 60)} minutes ago`
    if (seconds < 86400) return `${Math.floor(seconds / 3600)} hours ago`
    if (seconds < 604800) return `${Math.floor(seconds / 86400)} days ago`
    return date.toLocaleDateString()
  }

  const handleSendNotification = async () => {
    // Mock send notification
