                            <XCircle className="w-5 h-5 text-red-600" />
                          )}
                          <span className="font-medium">{log.event}</span>
                          {log.status_code && (
                            <span className="px-2 py-1 bg-white rounded text-sm">
                              Status: {log.status_code}
                            </span>
                          )}
                        </div>
                        <span className="text-sm text-gray-600">
                          {new Date(log.timestamp).toLocaleString()}
                        </span>
                      </div>
                      {log.error && (
                        <div className="mt-2 p-2 bg-white rounded text-sm text-red-600">
                          {log.error}
                        </div>
                      )}
                    </div>
                  ))}
                </div>
              )}
            </div>
          </motion.div>
        </div>
      )}
    </div>
  )
}

import { useState, useEffect, useRef } from 'react'
import { useAuthStore } from '../../store/globalStore'
import {
  Send,
  Bot,
  User,
  Sparkles,
  BookOpen,
  Code,
  Calculator,
  Brain,
  MessageSquare,
  Trash2,
  Lightbulb,
} from 'lucide-react'

interface Message {
  id: string
  role: 'user' | 'assistant'
  content: string
  timestamp: Date
  type?: 'text' | 'code' | 'math' | 'concept'
}

interface ConversationHistory {
  id: string
  title: string
  messages: Message[]
  subject: string
  lastUpdated: Date
}

export default function AITutorPage() {
  const { user } = useAuthStore()
  const [messages, setMessages] = useState<Message[]>([])
  const [input, setInput] = useState('')
  const [isTyping, setIsTyping] = useState(false)
  const [selectedSubject, setSelectedSubject] = useState<string>('general')
  const [conversations, setConversations] = useState<ConversationHistory[]>([])
  const [currentConversationId, setCurrentConversationId] = useState<string | null>(null)
  const [showHistory, setShowHistory] = useState(false)
  const messagesEndRef = useRef<HTMLDivElement>(null)
  const inputRef = useRef<HTMLTextAreaElement>(null)

  const subjects = [
    { value: 'general', label: 'General', icon: MessageSquare },
    { value: 'programming', label: 'Programming', icon: Code },
    { value: 'mathematics', label: 'Mathematics', icon: Calculator },
    { value: 'concepts', label: 'Concepts', icon: Brain },
    { value: 'dbms', label: 'DBMS', icon: BookOpen },
  ]

  useEffect(() => {
    loadConversationHistory()
    // Welcome message
    if (messages.length === 0) {
      addMessage({
        id: Date.now().toString(),
        role: 'assistant',
        content: `Hello ${user?.full_name?.split(' ')[0] || 'there'}! ≡ƒæï I'm your AI tutor. I can help you with:\n\nΓÇó Programming concepts and code examples\nΓÇó Mathematical problems and explanations\nΓÇó Database queries and design\nΓÇó General academic questions\nΓÇó Exam preparation tips\n\nWhat would you like to learn about today?`,
        timestamp: new Date(),
        type: 'text',
      })
    }
  }, [])

  useEffect(() => {
    scrollToBottom()
  }, [messages])

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' })
  }

  const loadConversationHistory = () => {
    // Mock conversation history
    const mockHistory: ConversationHistory[] = [
      {
        id: '1',
        title: 'Binary Search Trees',
        subject: 'programming',
        messages: [],
        lastUpdated: new Date('2024-10-30'),
      },
      {
        id: '2',
        title: 'SQL Joins Explained',
        subject: 'dbms',
        messages: [],
        lastUpdated: new Date('2024-10-29'),
      },
    ]
    setConversations(mockHistory)
  }

  const addMessage = (message: Message) => {
    setMessages(prev => [...prev, message])
  }

  const handleSend = async () => {
    if (!input.trim()) return

    const userMessage: Message = {
      id: Date.now().toString(),
      role: 'user',
      content: input,
      timestamp: new Date(),
      type: 'text',
    }

    addMessage(userMessage)
    setInput('')
    setIsTyping(true)

    // Simulate AI response
    setTimeout(() => {
      const aiResponse = generateAIResponse(input, selectedSubject)
      addMessage(aiResponse)
      setIsTyping(false)
    }, 1500)
  }

  const generateAIResponse = (query: string, subject: string): Message => {
    // Mock AI responses based on query
    const lowerQuery = query.toLowerCase()

    let response = ''
    let type: 'text' | 'code' | 'math' | 'concept' = 'text'

    if (lowerQuery.includes('binary search') || lowerQuery.includes('bst')) {
      type = 'code'
