  useEffect(() => {
    loadData()
  }, [])

  const loadData = async () => {
    try {
      const [examsData, resultsData] = await Promise.all([
        examAPI.getExams(user?.program),
        resultsAPI.getResults(),
      ])
      setExams(examsData)
      setResults(resultsData)
    } catch (error) {
