                  <span className="text-red-400 font-bold">{darkRoomBrightness}/255</span>
                </div>
                <div className="h-2 bg-gray-800 rounded-full overflow-hidden mb-3">
                  <div
                    className="h-full bg-gradient-to-r from-red-600 to-orange-500 rounded-full"
                    style={{ width: `${Math.min(100, (darkRoomBrightness / 255) * 100)}%` }}
                  />
                </div>
                <p className="text-yellow-400 text-xs font-semibold">Required: 30/255 minimum</p>
              </div>
              <div className="text-left bg-gray-900 rounded-xl p-4 mb-6 space-y-2">
                <p className="text-gray-300 text-sm font-semibold mb-2">To fix this:</p>
                <p className="text-gray-400 text-sm">Γ£à Turn on your room lights</p>
                <p className="text-gray-400 text-sm">Γ£à Face a window or bright light source</p>
                <p className="text-gray-400 text-sm">Γ£à Avoid sitting with backlight behind you</p>
                <p className="text-gray-400 text-sm">Γ£à Remove any camera covers or obstructions</p>
              </div>
              <motion.button
                whileHover={{ scale: 1.03 }}
                whileTap={{ scale: 0.97 }}
                onClick={() => {
                  // Re-check brightness
                  if (videoRef.current && videoRef.current.readyState >= 2) {
                    const canvas = document.createElement('canvas')
                    canvas.width = 64
                    canvas.height = 48
                    const ctx = canvas.getContext('2d')
                    if (ctx) {
                      ctx.drawImage(videoRef.current, 0, 0, 64, 48)
                      const imgData = ctx.getImageData(0, 0, 64, 48).data
                      let total = 0
                      for (let i = 0; i < imgData.length; i += 4) {
                        total +=
                          0.299 * imgData[i] + 0.587 * imgData[i + 1] + 0.114 * imgData[i + 2]
                      }
                      const brightness = total / (imgData.length / 4)
                      setDarkRoomBrightness(Math.round(brightness))
                      if (brightness >= 30) {
                        setDarkRoomBlocked(false)
                        setExamStarted(true)
                        requestFullscreen()
                        toast.success('Γ£à Lighting verified ΓÇö exam starting!', { duration: 3000 })
