                    color: 'bg-green-100 border border-green-300',
                    label: `Answered (${answeredCount})`,
                  },
                  {
                    color: 'bg-amber-100 border border-amber-300',
                    label: `Flagged (${flaggedCount})`,
                  },
                  {
                    color: 'bg-gray-100 border border-gray-300',
                    label: `Remaining (${(exam?.questions.length || 0) - answeredCount - flaggedCount})`,
                  },
                ].map(({ color, label }) => (
                  <div key={label} className="flex items-center gap-2">
                    <div className={`w-3 h-3 rounded shrink-0 ${color}`} />
                    <span>{label}</span>
                  </div>
                ))}
              </div>

              <div className="border-t border-gray-100 pt-3">
                <button
                  onClick={handleSubmitClick}
                  disabled={submitting}
                  className="w-full py-3 bg-gradient-to-r from-green-500 to-emerald-600 text-white rounded-xl font-bold text-sm hover:from-green-600 hover:to-emerald-700 transition-all disabled:opacity-60 shadow-lg shadow-green-500/20"
                >
                  {submitting ? (
                    <>
                      <div className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin" />
                      Submitting...
                    </>
                  ) : (
                    'Submit Exam'
                  )}
                </button>
                <p className="text-center text-xs text-gray-400 mt-2">
                  {(exam?.questions.length || 0) - answeredCount} questions unanswered
                </p>
              </div>
            </div>
          </div>

          {/* ΓöÇΓöÇΓöÇ Question Area ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ */}
          <div className="lg:col-span-7 space-y-4">
            {/* Progress */}
            <div className="bg-white rounded-2xl shadow-sm border border-gray-100 p-4 premium-card">
              <div className="flex items-center justify-between mb-2">
                <div className="flex items-center gap-3 text-xs text-gray-500">
                  <span className="flex items-center gap-1">
                    <div className="w-2.5 h-2.5 rounded-sm bg-green-400" />
                    Answered ({answeredCount})
                  </span>
                  <span className="flex items-center gap-1">
                    <div className="w-2.5 h-2.5 rounded-sm bg-amber-400" />
                    Flagged ({flaggedCount})
                  </span>
                  <span className="flex items-center gap-1">
                    <div className="w-2.5 h-2.5 rounded-sm bg-gray-200" />
                    Remaining ({exam?.questions.length - answeredCount})
                  </span>
                </div>
                <span className="text-xs font-semibold text-gray-900">
                  {currentQuestionIndex + 1}/{exam?.questions.length}
                </span>
              </div>

              {/* Segmented progress */}
              <div className="flex gap-0.5 h-2">
                {exam?.questions.map((_: any, idx: number) => {
                  const qId = exam.questions[idx]?._id || exam.questions[idx]?.id || idx.toString()
                  const state = getQuestionState(qId, idx)
                  return (
                    <div
                      key={idx}
                      className={`flex-1 rounded-full transition-all duration-300 ${
                        state === 'current'
                          ? 'bg-blue-500'
                          : state === 'answered'
                            ? 'bg-green-400'
                            : state === 'flagged'
                              ? 'bg-amber-400'
                              : 'bg-gray-200'
                      }`}
                    />
                  )
                })}
              </div>
            </div>

            {/* Question Card */}
            <motion.div
              key={currentQuestionIndex}
              initial={{ opacity: 0, x: 20 }}
              animate={{ opacity: 1, x: 0 }}
              transition={{ duration: 0.25 }}
              className="bg-white rounded-2xl shadow-sm border border-gray-100 p-5 sm:p-8 premium-card"
              {...swipeHandlers}
            >
              {/* Question Header */}
              <div className="flex items-start justify-between mb-5 gap-3">
                <div className="flex-1">
                  <div className="flex items-center gap-2 mb-2 flex-wrap">
                    <span className="bg-blue-50 text-blue-700 text-xs font-semibold px-2.5 py-1 rounded-lg border border-blue-100">
                      Question {currentQuestionIndex + 1}
                    </span>
                    {currentQuestion?.points && (
                      <span className="bg-gray-50 text-gray-600 text-xs px-2.5 py-1 rounded-lg border border-gray-200">
                        <Zap className="w-3 h-3 inline mr-0.5" />
                        {currentQuestion.points} pt{currentQuestion.points !== 1 ? 's' : ''}
                      </span>
                    )}
                    {currentQuestion?.difficulty && (
                      <span
                        className={`text-xs px-2.5 py-1 rounded-lg border font-medium ${
                          currentQuestion.difficulty === 'easy'
                            ? 'bg-green-50 text-green-700 border-green-100'
                            : currentQuestion.difficulty === 'medium'
                              ? 'bg-yellow-50 text-yellow-700 border-yellow-100'
                              : 'bg-red-50 text-red-700 border-red-100'
                        }`}
                      >
                        {currentQuestion.difficulty}
                      </span>
                    )}
                    {flaggedQuestions.has(currentQuestionId) && (
                      <span className="bg-amber-50 text-amber-700 text-xs px-2.5 py-1 rounded-lg border border-amber-200 flex items-center gap-1">
                        <Flag className="w-3 h-3" />
                        Flagged
                      </span>
                    )}
                  </div>
                  <p className="text-gray-900 text-sm sm:text-base leading-relaxed font-medium">
                    {currentQuestion?.question_text ||
                      currentQuestion?.question ||
                      'Question text not available'}
                  </p>
                </div>

                {/* Flag button */}
                <button
                  onClick={() => toggleQuestionFlag(currentQuestionId)}
                  title={
                    flaggedQuestions.has(currentQuestionId) ? 'Unflag question' : 'Flag for review'
                  }
                  className={`shrink-0 w-10 h-10 rounded-xl flex items-center justify-center transition-all ${
                    flaggedQuestions.has(currentQuestionId)
                      ? 'bg-amber-100 text-amber-600 hover:bg-amber-200 border border-amber-300'
                      : 'bg-gray-100 text-gray-400 hover:bg-gray-200 hover:text-amber-500 border border-gray-200'
                  }`}
                >
                  <Flag
                    className="w-4 h-4"
                    fill={flaggedQuestions.has(currentQuestionId) ? 'currentColor' : 'none'}
                  />
                </button>
              </div>

              {/* Answer Options */}
              {renderQuestion(currentQuestion, currentQuestionIndex)}

              {/* Mobile swipe hint */}
              {(isMobile || isTablet) && (
                <p className="mt-5 text-center text-xs text-gray-300">
                  ΓåÉ Swipe to navigate questions ΓåÆ
                </p>
              )}
            </motion.div>

            {/* Navigation Buttons */}
            <div className="flex items-center justify-between gap-3">
              <button
                onClick={prevQuestion}
                disabled={currentQuestionIndex === 0}
                className="flex items-center justify-center gap-2 px-5 sm:px-6 py-3 min-h-[48px] bg-white border-2 border-gray-200 rounded-xl hover:bg-gray-50 hover:border-gray-300 disabled:opacity-40 disabled:cursor-not-allowed transition-all font-medium text-sm text-gray-700 touch-manipulation flex-1 sm:flex-initial"
              >
                <ChevronLeft className="w-4 h-4 sm:w-5 sm:h-5" />
                Previous
              </button>

              {currentQuestionIndex === exam?.questions.length - 1 ? (
                <button
                  onClick={handleSubmitClick}
                  disabled={submitting}
                  className="flex items-center justify-center gap-2 px-5 sm:px-8 py-3 min-h-[48px] bg-gradient-to-r from-green-500 to-emerald-600 text-white rounded-xl hover:from-green-600 hover:to-emerald-700 disabled:opacity-60 transition-all font-semibold text-sm shadow-lg shadow-green-500/25 touch-manipulation flex-1 sm:flex-initial"
                >
                  {submitting ? (
                    <>
                      <div className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin" />
                      Submitting...
                    </>
                  ) : (
                    <>Submit Exam</>
                  )}
                </button>
              ) : (
                <button
                  onClick={nextQuestion}
                  className="flex items-center justify-center gap-2 px-5 sm:px-6 py-3 min-h-[48px] bg-gradient-to-r from-blue-600 to-indigo-600 text-white rounded-xl hover:from-blue-700 hover:to-indigo-700 transition-all font-medium text-sm shadow-lg shadow-blue-500/20 touch-manipulation flex-1 sm:flex-initial"
                >
                  Next
                  <ChevronRight className="w-4 h-4 sm:w-5 sm:h-5" />
                </button>
              )}
            </div>
          </div>

          {/* ΓöÇΓöÇΓöÇ Proctoring Right Panel ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ */}
          <div className="hidden lg:block lg:col-span-3 overflow-y-auto max-h-[calc(100vh-5rem)]">
            <ProctoringRightPanel
              videoRef={videoRef}
              proctoringActive={proctoringActive}
              cameraReady={cameraReady}
              trustScore={trustScore}
              proctoringStatus={
                proctoringStatus
                  ? {
                      faceDetected: proctoringStatus.faceDetected,
                      lookingAtScreen: proctoringStatus.lookingAtScreen,
                      faceCount: proctoringStatus.faceCount,
                      audioLevel: proctoringStatus.audioLevel,
                      isActive: proctoringStatus.isActive,
                      integrityScore: proctoringStatus.integrityScore,
                    }
                  : null
              }
              audioWaveData={audioWaveData}
              tabSwitches={tabSwitches}
              flags={flags}
              mode="live"
            />
          </div>
        </div>
      </div>

      {/* ΓöÇΓöÇΓöÇ Modals ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ */}
      <ExamSubmitModal
        isOpen={showSubmitModal}
        onConfirm={doSubmitExam}
        onCancel={() => setShowSubmitModal(false)}
        examTitle={exam?.title || ''}
        totalQuestions={exam?.questions.length || 0}
        answeredCount={answeredCount}
        flaggedCount={flaggedCount}
        timeTaken={timeTaken}
        violationCount={violationCount}
        trustScore={trustScore}
        submitting={submitting}
      />

      <ExamTimerWarning
        isOpen={showTimerWarning}
        minutesLeft={timerWarningMinutes}
        onDismiss={() => setShowTimerWarning(false)}
      />
    </div>
  )
}

import { useState, useEffect } from 'react'
import { useNavigate, useParams, useLocation } from 'react-router-dom'
import {
  CheckCircle,
  XCircle,
  TrendingUp,
  Home,
  ChevronRight,
  AlertCircle,
  BarChart3,
  Trophy,
} from 'lucide-react'
import { resultsAPI } from '../../lib/api'
import { motion } from 'framer-motion'
import { toast } from 'sonner'

interface SubmissionResult {
  _id: string
  exam_id: string
  exam_title: string
  student_name: string
  score: number
  total: number
  percentage: number
  time_taken: number
  date: string
  passed: boolean
  proctoring_violations?: number
  detailed_results?: Array<{
    question: string
    student_answer: any
    correct_answer: any
    is_correct: boolean
    explanation?: string
    marks?: number
  }>
}

export default function ExamResultPage() {
  const navigate = useNavigate()
  const { submissionId } = useParams()
  const location = useLocation()
  const [loading, setLoading] = useState(true)
  const [error, setError] = useState<string | null>(null)
  const [result, setResult] = useState<SubmissionResult | null>(null)
  const [allResults, setAllResults] = useState<SubmissionResult[]>([])
  const initialResult = (location.state as { result?: SubmissionResult } | null)?.result

  useEffect(() => {
    if (initialResult) {
      setResult(initialResult)
      setLoading(false)
      setError(null)
      return
    }
    loadResults()
  }, [submissionId, initialResult])

  const loadResults = async () => {
    try {
      setLoading(true)
      setError(null)

      if (submissionId) {
        // Load specific submission
        const data = await resultsAPI.getResult(submissionId)
        setResult(data)
      } else {
        // Load all results for the student
        const data = await resultsAPI.getResults()
        setAllResults(data)
        // Show the most recent result if available
        if (data && data.length > 0) {
          setResult(data[0])
        }
      }
    } catch (error: any) {
      console.error('Failed to load results:', error)
      setError(error?.response?.data?.detail || 'Failed to load results')
      toast.error('Could not load exam results')
    } finally {
      setLoading(false)
    }
  }

  const formatTime = (seconds: number) => {
    if (!seconds) return 'N/A'
    const mins = Math.floor(seconds / 60)
    const secs = seconds % 60
    return `${mins}m ${secs}s`
  }

  const formatDate = (dateStr: string) => {
    if (!dateStr) return 'N/A'
    try {
      return new Date(dateStr).toLocaleDateString('en-IN', {
        year: 'numeric',
        month: 'long',
        day: 'numeric',
        hour: '2-digit',
        minute: '2-digit',
      })
    } catch {
      return dateStr
    }
  }

  const getGrade = (percentage: number) => {
    if (percentage >= 90) return { grade: 'A+', color: 'text-green-600' }
    if (percentage >= 80) return { grade: 'A', color: 'text-green-600' }
    if (percentage >= 70) return { grade: 'B', color: 'text-blue-600' }
    if (percentage >= 60) return { grade: 'C', color: 'text-yellow-600' }
    if (percentage >= 50) return { grade: 'D', color: 'text-orange-600' }
    return { grade: 'F', color: 'text-red-600' }
  }

  if (loading) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-gradient-to-br from-gray-50 to-blue-50">
        <div className="text-center">
          <div className="animate-spin rounded-full h-16 w-16 border-b-4 border-blue-600 mx-auto mb-4"></div>
          <p className="text-gray-600 font-medium">Loading results...</p>
        </div>
      </div>
    )
  }

  if (error || !result) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-gradient-to-br from-gray-50 to-blue-50">
        <div className="text-center bg-white rounded-2xl shadow-lg p-10 max-w-md">
          <AlertCircle className="w-16 h-16 text-red-500 mx-auto mb-4" />
          <h2 className="text-2xl font-bold text-gray-900 mb-2">No Results Found</h2>
          <p className="text-gray-600 mb-6">
            {error || "You haven't taken any exams yet. Complete an exam to see your results."}
          </p>
          <button
            onClick={() => navigate('/student/dashboard')}
            className="bg-blue-600 text-white px-6 py-3 rounded-lg hover:bg-blue-700 transition font-semibold"
          >
            Go to Dashboard
          </button>
        </div>
      </div>
    )
  }

  const isPassed = result.passed
  const gradeInfo = getGrade(result.percentage)
  const correctCount = result.detailed_results?.filter(q => q.is_correct).length ?? result.score
  const wrongCount = result.detailed_results
    ? result.detailed_results.filter(q => !q.is_correct).length
    : result.total - result.score

  return (
    <div className="min-h-screen bg-gradient-to-br from-gray-50 to-blue-50 py-8">
      <div className="max-w-5xl mx-auto px-4">
        {/* All Results Selector */}
        {allResults.length > 1 && (
          <div className="mb-6 bg-white rounded-xl shadow-sm p-4 flex items-center gap-4 overflow-x-auto">
            <span className="text-sm font-medium text-gray-600 whitespace-nowrap">
              Recent Results:
            </span>
            {allResults.slice(0, 5).map((r, i) => (
              <button
                key={r._id}
                onClick={() => setResult(r)}
                className={`px-4 py-2 rounded-lg text-sm font-medium whitespace-nowrap transition ${
                  result._id === r._id
                    ? 'bg-blue-600 text-white'
                    : 'bg-gray-100 text-gray-700 hover:bg-gray-200'
                }`}
              >
                {r.exam_title || `Exam ${i + 1}`} ({r.percentage?.toFixed(0)}%)
              </button>
            ))}
          </div>
        )}

        {/* Result Header */}
        <motion.div
          initial={{ opacity: 0, y: -20 }}
          animate={{ opacity: 1, y: 0 }}
          className={`rounded-2xl shadow-xl p-8 mb-8 ${
            isPassed
              ? 'bg-gradient-to-br from-green-600 via-emerald-600 to-teal-600'
              : 'bg-gradient-to-br from-red-600 via-orange-600 to-amber-600'
          } text-white`}
        >
          <div className="flex items-center justify-between mb-6 flex-wrap gap-4">
            <div className="flex items-center space-x-4">
              {isPassed ? (
                <div className="bg-white/20 rounded-full p-3">
                  <CheckCircle className="w-12 h-12" />
                </div>
              ) : (
                <div className="bg-white/20 rounded-full p-3">
                  <XCircle className="w-12 h-12" />
                </div>
              )}
              <div>
                <h1 className="text-3xl font-bold">
                  {isPassed ? '≡ƒÄë Congratulations!' : '≡ƒÆ¬ Keep Going!'}
                </h1>
                <p className="text-white/80 text-lg">{result.exam_title || 'Exam Result'}</p>
                <p className="text-white/60 text-sm">{formatDate(result.date)}</p>
              </div>
            </div>
            <div className="text-right">
              <div className="text-6xl font-bold">{result.percentage?.toFixed(1)}%</div>
              <div className="text-xl">
                Grade: <span className="font-bold">{gradeInfo.grade}</span>
              </div>
              <div className="text-white/80 font-medium mt-1">
                {isPassed ? 'Γ£à PASSED' : 'Γ¥î FAILED'}
              </div>
            </div>
          </div>

          <div className="grid grid-cols-2 sm:grid-cols-4 gap-4 mt-4">
            <div className="bg-white/20 rounded-xl p-4 backdrop-blur-sm">
              <p className="text-sm text-white/80 mb-1">Score</p>
              <p className="text-2xl font-bold">
                {result.score}/{result.total}
              </p>
            </div>
            <div className="bg-white/20 rounded-xl p-4 backdrop-blur-sm">
              <p className="text-sm text-white/80 mb-1">Time Taken</p>
              <p className="text-2xl font-bold">{formatTime(result.time_taken)}</p>
            </div>
            <div className="bg-white/20 rounded-xl p-4 backdrop-blur-sm">
              <p className="text-sm text-white/80 mb-1">Correct</p>
              <p className="text-2xl font-bold text-green-300">{correctCount}</p>
            </div>
            <div className="bg-white/20 rounded-xl p-4 backdrop-blur-sm">
              <p className="text-sm text-white/80 mb-1">Violations</p>
              <p className="text-2xl font-bold text-yellow-300">
                {result.proctoring_violations || 0}
              </p>
            </div>
          </div>
        </motion.div>

        {/* Performance Overview */}
        <motion.div
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ delay: 0.1 }}
          className="grid md:grid-cols-3 gap-6 mb-8"
        >
          <div className="bg-white rounded-xl shadow-sm p-6 border border-green-100">
            <div className="flex items-center justify-between mb-4">
              <h3 className="font-semibold text-gray-700">Correct Answers</h3>
              <CheckCircle className="w-6 h-6 text-green-600" />
            </div>
            <p className="text-4xl font-bold text-green-600">{correctCount}</p>
            <div className="mt-3">
              <div className="flex items-center justify-between text-sm text-gray-600 mb-1">
                <span>Accuracy</span>
                <span>
                  {result.total > 0 ? Math.round((correctCount / result.total) * 100) : 0}%
                </span>
              </div>
              <div className="flex-1 bg-gray-200 rounded-full h-2">
                <div
                  className="bg-green-500 h-2 rounded-full transition-all"
                  style={{
                    width: `${result.total > 0 ? (correctCount / result.total) * 100 : 0}%`,
                  }}
                ></div>
              </div>
            </div>
          </div>

          <div className="bg-white rounded-xl shadow-sm p-6 border border-red-100">
            <div className="flex items-center justify-between mb-4">
              <h3 className="font-semibold text-gray-700">Wrong Answers</h3>
              <XCircle className="w-6 h-6 text-red-600" />
            </div>
            <p className="text-4xl font-bold text-red-600">{wrongCount}</p>
            <div className="mt-3">
              <div className="flex items-center justify-between text-sm text-gray-600 mb-1">
                <span>Error Rate</span>
                <span>{result.total > 0 ? Math.round((wrongCount / result.total) * 100) : 0}%</span>
              </div>
              <div className="flex-1 bg-gray-200 rounded-full h-2">
                <div
                  className="bg-red-500 h-2 rounded-full transition-all"
                  style={{ width: `${result.total > 0 ? (wrongCount / result.total) * 100 : 0}%` }}
                ></div>
              </div>
            </div>
          </div>

          <div className="bg-white rounded-xl shadow-sm p-6 border border-blue-100">
            <div className="flex items-center justify-between mb-4">
              <h3 className="font-semibold text-gray-700">Performance</h3>
              <BarChart3 className="w-6 h-6 text-blue-600" />
            </div>
            <p className={`text-4xl font-bold ${gradeInfo.color}`}>{gradeInfo.grade}</p>
            <div className="mt-3">
              <div className="flex items-center justify-between text-sm text-gray-600 mb-1">
                <span>Score</span>
                <span>{result.percentage?.toFixed(1)}%</span>
              </div>
              <div className="flex-1 bg-gray-200 rounded-full h-2">
                <div
                  className="bg-blue-500 h-2 rounded-full transition-all"
                  style={{ width: `${result.percentage || 0}%` }}
                ></div>
              </div>
            </div>
          </div>
        </motion.div>

        {/* Trust Score */}
        {result.proctoring_violations !== undefined && (
          <motion.div
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ delay: 0.2 }}
            className="bg-white rounded-xl shadow-sm p-6 mb-8 border border-indigo-100"
          >
            <h3 className="text-xl font-bold mb-4 flex items-center">
              <Trophy className="w-5 h-5 mr-2 text-indigo-600" />
              Integrity & Trust Score
            </h3>
            <div className="flex items-center gap-6">
              <div className="text-center">
                <div
                  className={`text-5xl font-bold ${
                    result.proctoring_violations === 0
                      ? 'text-green-600'
                      : result.proctoring_violations <= 2
                        ? 'text-yellow-600'
                        : 'text-red-600'
                  }`}
                >
                  {Math.max(0, 100 - (result.proctoring_violations || 0) * 10)}%
                </div>
                <p className="text-sm text-gray-500 mt-1">Trust Score</p>
              </div>
              <div className="flex-1">
                <div className="flex items-center justify-between text-sm mb-1">
                  <span className="text-gray-600">Proctoring Violations</span>
                  <span
                    className={`font-semibold ${
                      result.proctoring_violations === 0 ? 'text-green-600' : 'text-red-600'
                    }`}
                  >
                    {result.proctoring_violations || 0}
                  </span>
                </div>
                <div className="w-full bg-gray-200 rounded-full h-3">
                  <div
                    className={`h-3 rounded-full transition-all ${
                      result.proctoring_violations === 0
                        ? 'bg-green-500'
                        : result.proctoring_violations <= 2
                          ? 'bg-yellow-500'
                          : 'bg-red-500'
                    }`}
                    style={{
                      width: `${Math.max(0, 100 - (result.proctoring_violations || 0) * 10)}%`,
                    }}
                  ></div>
                </div>
                <p className="text-sm text-gray-500 mt-2">
                  {result.proctoring_violations === 0
                    ? 'Γ£à Perfect integrity - no violations detected'
                    : `ΓÜá∩╕Å ${result.proctoring_violations} violation(s) recorded during the exam`}
                </p>
              </div>
            </div>
          </motion.div>
        )}

        {/* Question Review - Always Visible */}
        {result.detailed_results && result.detailed_results.length > 0 && (
          <motion.div
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ delay: 0.3 }}
            className="bg-white rounded-2xl shadow-sm mb-8 overflow-hidden border border-gray-100"
          >
            {/* Header */}
            <div className="flex items-center justify-between px-6 py-5 border-b border-gray-100 bg-gradient-to-r from-gray-50 to-white">
              <div>
                <h3 className="text-xl font-bold text-gray-900">≡ƒôï Question Review</h3>
                <p className="text-sm text-gray-500 mt-0.5">
                  {result.detailed_results.filter(q => q.is_correct).length} correct out of{' '}
                  {result.detailed_results.length} questions
                </p>
              </div>
              <div className="flex items-center gap-3">
                <div className="flex items-center gap-2 text-xs">
                  <div className="w-3 h-3 rounded-full bg-green-500" />
                  <span className="text-gray-600 font-medium">Correct</span>
                </div>
                <div className="flex items-center gap-2 text-xs">
                  <div className="w-3 h-3 rounded-full bg-red-500" />
                  <span className="text-gray-600 font-medium">Wrong</span>
                </div>
                <div className="flex items-center gap-2 text-xs">
                  <div className="w-3 h-3 rounded-full bg-gray-300" />
                  <span className="text-gray-600 font-medium">Skipped</span>
                </div>
              </div>
            </div>

            {/* Questions List */}
            <div className="divide-y divide-gray-50">
              {result.detailed_results.map((q, index) => {
                const isSkipped =
                  q.student_answer === null ||
                  q.student_answer === undefined ||
                  q.student_answer === ''
                return (
                  <div
                    key={index}
                    className={`p-5 sm:p-6 transition-colors ${
                      isSkipped ? 'bg-gray-50/50' : q.is_correct ? 'bg-green-50/30' : 'bg-red-50/30'
                    }`}
                  >
                    {/* Question Row Header */}
                    <div className="flex items-start gap-3 mb-4">
                      {/* Status Icon */}
                      <div
                        className={`flex-shrink-0 w-8 h-8 rounded-full flex items-center justify-center text-sm font-bold ${
                          isSkipped
                            ? 'bg-gray-100 text-gray-500'
                            : q.is_correct
                              ? 'bg-green-100 text-green-700'
                              : 'bg-red-100 text-red-700'
                        }`}
                      >
                        {isSkipped ? 'ΓÇö' : q.is_correct ? 'Γ£ô' : 'Γ£ù'}
                      </div>
                      <div className="flex-1">
                        {/* Q# and marks */}
                        <div className="flex items-center justify-between mb-1">
                          <span
                            className={`text-xs font-bold uppercase tracking-wide px-2 py-0.5 rounded-full ${
                              isSkipped
                                ? 'bg-gray-100 text-gray-500'
                                : q.is_correct
                                  ? 'bg-green-100 text-green-700'
                                  : 'bg-red-100 text-red-700'
                            }`}
                          >
                            Q{index + 1} ΓÇó{' '}
                            {isSkipped ? 'Skipped' : q.is_correct ? 'Correct' : 'Incorrect'}
                          </span>
                          <span className="text-xs text-gray-400 font-medium">
                            {q.is_correct ? q.marks || 1 : 0}/{q.marks || 1}{' '}
                            {(q.marks || 1) === 1 ? 'mark' : 'marks'}
                          </span>
                        </div>
                        {/* Question Text */}
                        <p className="text-gray-900 text-sm sm:text-base font-medium leading-relaxed">
                          {q.question || 'Question text unavailable'}
                        </p>
                      </div>
                    </div>

                    {/* Answers grid */}
                    <div className="ml-11 grid sm:grid-cols-2 gap-3">
                      {/* Student's Answer */}
                      <div
                        className={`rounded-xl p-3 border ${
                          isSkipped
                            ? 'bg-gray-50 border-gray-200'
                            : q.is_correct
                              ? 'bg-green-50 border-green-200'
                              : 'bg-red-50 border-red-200'
                        }`}
                      >
                        <p className="text-xs font-bold text-gray-500 uppercase tracking-wide mb-1.5">
                          Your Answer
                        </p>
                        <p
                          className={`text-sm font-semibold ${
                            isSkipped
                              ? 'text-gray-400 italic'
                              : q.is_correct
                                ? 'text-green-800'
                                : 'text-red-800'
                          }`}
                        >
                          {isSkipped
                            ? 'Not answered'
                            : Array.isArray(q.student_answer)
                              ? q.student_answer.join(', ')
                              : String(q.student_answer)}
                        </p>
                      </div>

                      {/* Correct Answer ΓÇö always shown */}
                      <div className="bg-green-50 border border-green-200 rounded-xl p-3">
                        <p className="text-xs font-bold text-gray-500 uppercase tracking-wide mb-1.5">
                          Correct Answer
                        </p>
                        <p className="text-sm font-semibold text-green-800">
                          {q.correct_answer !== null && q.correct_answer !== undefined ? (
                            Array.isArray(q.correct_answer) ? (
                              q.correct_answer.join(', ')
                            ) : (
                              String(q.correct_answer)
                            )
                          ) : (
                            <span className="text-gray-400 italic">N/A</span>
                          )}
                        </p>
                      </div>
                    </div>

                    {/* Explanation */}
                    {q.explanation && (
                      <div className="ml-11 mt-3 bg-blue-50 border-l-4 border-blue-400 rounded-r-xl p-3">
                        <p className="text-xs font-bold text-blue-700 mb-1">≡ƒÆí Explanation</p>
                        <p className="text-sm text-gray-700 leading-relaxed">{q.explanation}</p>
                      </div>
                    )}
                  </div>
                )
              })}
            </div>
          </motion.div>
        )}

        {/* Action Buttons */}
        <motion.div
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ delay: 0.4 }}
          className="flex items-center justify-between flex-wrap gap-4"
        >
          <button
            onClick={() => navigate('/student/dashboard')}
            className="flex items-center space-x-2 px-6 py-3 border-2 border-gray-300 rounded-xl hover:bg-gray-50 transition font-medium"
          >
            <Home className="w-5 h-5" />
            <span>Back to Dashboard</span>
          </button>
          <div className="flex items-center space-x-4 flex-wrap gap-3">
            <button
              onClick={() => navigate('/practice')}
              className="flex items-center space-x-2 px-6 py-3 bg-indigo-600 text-white rounded-xl hover:bg-indigo-700 transition font-medium"
            >
              <TrendingUp className="w-5 h-5" />
              <span>Practice More</span>
            </button>
            <button
              onClick={() => navigate('/student/dashboard')}
              className="flex items-center space-x-2 px-6 py-3 bg-green-600 text-white rounded-xl hover:bg-green-700 transition font-medium"
            >
              <span>Take Another Exam</span>
              <ChevronRight className="w-5 h-5" />
            </button>
          </div>
        </motion.div>
      </div>
    </div>
  )
}

import { useEffect, useRef, useMemo, useCallback, useState } from 'react'
import { useParams, useNavigate } from 'react-router-dom'
import {
  AlertTriangle,
  Eye,
  Clock,
  Flag,
  ChevronLeft,
  ChevronRight,
  Menu,
  X,
  Brain,
  Trophy,
  TrendingUp,
  Maximize,
} from 'lucide-react'
import { useSwipe } from '../../hooks/useSwipe'
import { useMobileDetect } from '../../hooks/useMobileDetect'
import { useExamState } from '../../hooks/useExamState'
import { logger } from '../../lib/logger'
import { getQuestionsByCategory } from '../../data/questionBank'
import AdaptiveExamEngine, { DifficultyLevel } from '../../utils/adaptiveExamEngine'
import ProctoringEngine from '../../utils/proctoringEngine'
import type { ProctoringStatus } from '../../utils/proctoringEngine'
import ViolationWarning, {
  ProctoringStatusBar,
  ViolationSummary,
} from '../../components/ViolationWarning'
import ProctoringRightPanel from '../../components/ProctoringRightPanel'
import { AnimatePresence, motion } from 'framer-motion'
import { WebSocketClient } from '../../lib/websocket'
import { useAuthStore } from '../../store/globalStore'

interface Question {
  id: number
  text: string
  type: 'mcq' | 'multiple-answer' | 'true-false' | 'short-answer'
  options?: string[]
  correctAnswer: string | string[]
  points: number
  explanation: string
  difficulty: 'Easy' | 'Medium' | 'Hard'
}

interface MockTestData {
  id: string
  title: string
  category: string
  duration: number
  questions: Question[]
  passingScore: number
}

export default function PracticeMockExam() {
  const { testId } = useParams()
  const navigate = useNavigate()
  const { isMobile, isTablet } = useMobileDetect()
  const videoRef = useRef<HTMLVideoElement>(null)
  const sidebarVideoRef = useRef<HTMLVideoElement>(null)
  const wsClientRef = useRef<WebSocketClient | null>(null)
  const user = useAuthStore(state => state.user)
  const heartbeatRef = useRef<number | null>(null)
  const trustSyncRef = useRef<number | null>(null)

  // Mock test data based on testId
  const mockTestData: MockTestData = getMockTestData(testId || '')

  // Centralized state management with useExamState hook (replaces 20+ useState)
  const [examState, dispatch] = useExamState(mockTestData.duration)

  // Local state
  const [initMessage, setInitMessage] = useState('Preparing your exam...')
  const [audioWaveData, setAudioWaveData] = useState<number[]>([])
  const [showTimesUp, setShowTimesUp] = useState(false)

  // Proctoring Engine V1 (same as live exams)
  const proctoringEngine = useMemo(() => new ProctoringEngine(), [])

  // Adaptive Exam Engine
  const adaptiveEngine = useMemo(() => new AdaptiveExamEngine('Medium'), [])

  // Swipe handlers for mobile
  const swipeHandlers = useSwipe({
    onSwipeLeft: () => {
      if (examState.currentQuestion < mockTestData.questions.length - 1) {
        dispatch({ type: 'SET_CURRENT_QUESTION', payload: examState.currentQuestion + 1 })
      }
    },
    onSwipeRight: () => {
      if (examState.currentQuestion > 0) {
        dispatch({ type: 'SET_CURRENT_QUESTION', payload: examState.currentQuestion - 1 })
      }
    },
  })

  // Simple, reliable camera shutdown with logger
  const stopCamera = useCallback(async () => {
    try {
      logger.info('Stopping camera and proctoring')

      // Stop WebSocket
      if (wsClientRef.current) {
        wsClientRef.current.disconnect()
        wsClientRef.current = null
      }
      if (heartbeatRef.current) {
        clearInterval(heartbeatRef.current)
        heartbeatRef.current = null
      }
      if (trustSyncRef.current) {
        clearInterval(trustSyncRef.current)
        trustSyncRef.current = null
      }

      // Get all tracks and stop them
      const stopAllTracks = (videoEl: HTMLVideoElement | null) => {
        if (videoEl?.srcObject) {
          const stream = videoEl.srcObject as MediaStream
          stream.getTracks().forEach(track => track.stop())
          videoEl.srcObject = null
          videoEl.pause()
        }
      }

      stopAllTracks(videoRef.current)
      stopAllTracks(sidebarVideoRef.current)

      // Engine cleanup
      if (proctoringEngine) {
        await proctoringEngine.cleanup()
      }

      // Reset state using dispatch
      dispatch({ type: 'ENABLE_CAMERA', payload: false })
      dispatch({ type: 'ENABLE_MIC', payload: false })
      dispatch({ type: 'SET_PROCTORING_STATUS', payload: null })
      dispatch({ type: 'SET_ACTIVE_VIOLATIONS', payload: [] })

      // Wait for hardware release
      await new Promise(resolve => setTimeout(resolve, 1000))

      logger.info('Camera stopped successfully')
    } catch (error) {
      logger.error('Camera shutdown error', error)
    }
  }, [proctoringEngine, dispatch])

  // Cleanup on component unmount
  useEffect(() => {
    return () => {
      if (proctoringEngine) {
        proctoringEngine.cleanup()
      }

      const cleanupVideo = (ref: React.RefObject<HTMLVideoElement>) => {
        if (ref.current?.srcObject) {
          const stream = ref.current.srcObject as MediaStream
          stream.getTracks().forEach(track => track.stop())
          ref.current.srcObject = null
        }
      }

      cleanupVideo(videoRef)
      cleanupVideo(sidebarVideoRef)
    }
  }, [proctoringEngine])

  // Timer
  useEffect(() => {
    if (!examState.examStarted || examState.examEnded || examState.isSubmitting) return

    const timer = setInterval(() => {
      dispatch({ type: 'DECREMENT_TIME' })
    }, 1000)

    return () => clearInterval(timer)
  }, [examState.examStarted, examState.examEnded, examState.isSubmitting])

  // Auto-start exam when camera + proctoring are ready
  useEffect(() => {
    if (
      examState.cameraEnabled &&
      examState.proctoringStatus?.isActive &&
      !examState.examStarted &&
      !examState.isSubmitting
    ) {
      setInitMessage('Starting exam...')
      const timer = setTimeout(() => {
        handleStartExam(true)
      }, 800)
      return () => clearTimeout(timer)
    }
  }, [examState.cameraEnabled, examState.proctoringStatus?.isActive])

  // Auto-submit when time expires (separate effect)
  useEffect(() => {
    if (
      examState.examStarted &&
      !examState.examEnded &&
      !examState.isSubmitting &&
      examState.timeRemaining === 0 &&
      !showTimesUp
    ) {
      console.log('ΓÅ░ Time expired - showing times up notification')
      setShowTimesUp(true)
      setTimeout(() => {
        setShowTimesUp(false)
        handleSubmitExam()
      }, 3000)
    }
  }, [
    examState.timeRemaining,
    examState.examStarted,
    examState.examEnded,
    examState.isSubmitting,
    showTimesUp,
  ])

  // Real-time audio wave polling during exam
  useEffect(() => {
    if (!examState.examStarted || examState.examEnded) return
    const interval = setInterval(() => {
      const freqData = proctoringEngine.getAudioFrequencyData()
      if (freqData.length > 0) {
        setAudioWaveData(freqData.slice(0, 32))
      }
    }, 100)
    return () => clearInterval(interval)
  }, [examState.examStarted, examState.examEnded, proctoringEngine])

  // Start camera when camera not yet enabled
  useEffect(() => {
    if (!examState.cameraEnabled && !examState.isInitializingCamera) {
      startCamera()
    }
  }, [examState.cameraEnabled])

  // Update sidebar video stream when exam starts
  useEffect(() => {
    const connectSidebarVideo = async () => {
      if (examState.examStarted && examState.proctoringStatus?.isActive) {
        const stream = proctoringEngine.getStream()
        if (stream) {
          logger.debug('Connecting sidebar video stream')

          // Attach to sidebar video (small camera preview in UI)
          if (sidebarVideoRef.current) {
            sidebarVideoRef.current.srcObject = stream
            try {
              await sidebarVideoRef.current.play()
              logger.debug('Sidebar video playing', {
                width: sidebarVideoRef.current.videoWidth,
                height: sidebarVideoRef.current.videoHeight,
              })
            } catch (error) {
              logger.error('Failed to play sidebar video', error)
            }
          }

          // Also re-attach to main videoRef (ProctoringRightPanel's video)
          // This handles the case where the loading screen's <video> unmounted
          // and the ProctoringRightPanel's <video> just mounted with no srcObject
          if (videoRef.current) {
            videoRef.current.srcObject = stream
            try {
              await videoRef.current.play()
            } catch (error) {
              logger.error('Failed to play main video', error)
            }
          }
        } else {
          logger.warn('No stream available from proctoring engine')
        }
      }
    }

    connectSidebarVideo()

    // Cleanup sidebar video when exam ends
    return () => {
      if (sidebarVideoRef.current && !examState.examStarted) {
        sidebarVideoRef.current.srcObject = null
        logger.debug('Sidebar video cleared')
      }
    }
  }, [examState.proctoringStatus?.isActive, examState.examStarted])

  // Start monitoring when exam starts
  useEffect(() => {
    if (examState.examStarted && examState.proctoringStatus?.isActive) {
      // Monitoring is already started during camera initialization
      // Just ensure it's running
      if (!proctoringEngine.isMonitoringActive()) {
        logger.info('Starting monitoring for exam')
        proctoringEngine.startMonitoring()
      } else {
        logger.info('Monitoring already active from camera preview')
      }
    }
  }, [examState.examStarted, examState.proctoringStatus?.isActive, proctoringEngine])

  // Tab switch detection ΓÇö PAUSE exam immediately
  useEffect(() => {
    const handleVisibilityChange = () => {
      if (
        document.hidden &&
        examState.examStarted &&
        !examState.examEnded &&
        !examState.isSubmitting &&
        !examState.proctoringStatus?.isPaused
      ) {
        proctoringEngine.recordTabSwitch()
        proctoringEngine.pauseExam(
          'Tab/Window switch detected. Return to the exam window to resume.'
        )
      }
    }

    document.addEventListener('visibilitychange', handleVisibilityChange)
    return () => document.removeEventListener('visibilitychange', handleVisibilityChange)
  }, [
    examState.examStarted,
    examState.examEnded,
    examState.isSubmitting,
    examState.proctoringStatus?.isPaused,
  ])

  // Window blur detection ΓÇö PAUSE exam immediately
  useEffect(() => {
    const handleWindowBlur = () => {
      if (
        examState.examStarted &&
        !examState.examEnded &&
        !examState.isSubmitting &&
        !examState.proctoringStatus?.isPaused
      ) {
        proctoringEngine.recordWindowBlur()
        proctoringEngine.pauseExam('Application switch detected. Return to the exam to resume.')
      }
    }

    window.addEventListener('blur', handleWindowBlur)
    return () => window.removeEventListener('blur', handleWindowBlur)
  }, [
    examState.examStarted,
    examState.examEnded,
    examState.isSubmitting,
    examState.proctoringStatus?.isPaused,
  ])

  // Fullscreen enforcement ΓÇö PAUSE exam on exit
  useEffect(() => {
    const handleFullscreenChange = () => {
      const isNowFullscreen = !!document.fullscreenElement
      dispatch({ type: 'SET_FULLSCREEN', payload: isNowFullscreen })

      if (
        !isNowFullscreen &&
        examState.examStarted &&
        !examState.examEnded &&
        !examState.isSubmitting &&
        !examState.proctoringStatus?.isPaused
      ) {
        proctoringEngine.recordFullscreenExit()
        proctoringEngine.pauseExam(
          'Fullscreen mode was exited. Return to fullscreen to resume the exam.'
        )
      }
    }

    document.addEventListener('fullscreenchange', handleFullscreenChange)
    return () => document.removeEventListener('fullscreenchange', handleFullscreenChange)
  }, [
    examState.examStarted,
    examState.examEnded,
    examState.isSubmitting,
    examState.proctoringStatus?.isPaused,
  ])

  // Keyboard blocking (Alt+Tab, Meta/Windows, Escape, PrintScreen, Ctrl+P)
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (
        !examState.examStarted ||
        examState.examEnded ||
        examState.isSubmitting ||
        examState.proctoringStatus?.isPaused
      )
        return
      if ((e.ctrlKey && e.key === 'p') || e.key === 'PrintScreen') {
        e.preventDefault()
      }
      if (e.key === 'F12' || (e.ctrlKey && e.shiftKey && ['I', 'J', 'C'].includes(e.key))) {
        e.preventDefault()
      }
      if (e.ctrlKey && ['c', 'v', 'x', 's'].includes(e.key.toLowerCase())) {
        e.preventDefault()
      }
      if (e.altKey && e.key === 'Tab') {
        e.preventDefault()
        proctoringEngine.pauseExam('Alt+Tab detected. Stay focused on the exam to resume.')
      }
      if (e.key === 'Meta' || e.key === 'OS') {
        e.preventDefault()
        proctoringEngine.pauseExam('Windows key pressed. Stay focused on the exam to resume.')
      }
      if (e.key === 'Escape' && document.fullscreenElement) {
        e.preventDefault()
        proctoringEngine.recordFullscreenExit()
        proctoringEngine.pauseExam('Escape key pressed. Stay in fullscreen to continue the exam.')
      }
    }
    document.addEventListener('keydown', handleKeyDown)
    return () => document.removeEventListener('keydown', handleKeyDown)
  }, [
    examState.examStarted,
    examState.examEnded,
    examState.isSubmitting,
    examState.proctoringStatus?.isPaused,
  ])

  // Copy-Paste-Cut Blocking
  useEffect(() => {
    const handleClipboard = (e: ClipboardEvent) => {
      if (!examState.examStarted || examState.examEnded || examState.isSubmitting) return
      e.preventDefault()
    }
    document.addEventListener('copy', handleClipboard)
    document.addEventListener('paste', handleClipboard)
    document.addEventListener('cut', handleClipboard)
    return () => {
      document.removeEventListener('copy', handleClipboard)
      document.removeEventListener('paste', handleClipboard)
      document.removeEventListener('cut', handleClipboard)
    }
  }, [examState.examStarted, examState.examEnded, examState.isSubmitting])

  // Right-Click / Context Menu Blocking
  useEffect(() => {
    const handleContextMenu = (e: MouseEvent) => {
      if (!examState.examStarted || examState.examEnded || examState.isSubmitting) return
      e.preventDefault()
    }
    document.addEventListener('contextmenu', handleContextMenu)
    return () => document.removeEventListener('contextmenu', handleContextMenu)
  }, [examState.examStarted, examState.examEnded, examState.isSubmitting])

  // Text Selection Prevention
  useEffect(() => {
    const handleSelectStart = (e: Event) => {
      if (!examState.examStarted || examState.examEnded || examState.isSubmitting) return
      e.preventDefault()
    }
    document.addEventListener('selectstart', handleSelectStart)
    return () => document.removeEventListener('selectstart', handleSelectStart)
  }, [examState.examStarted, examState.examEnded, examState.isSubmitting])

  // Window size / taskbar detection ΓÇö PAUSE if minimized
  useEffect(() => {
    const checkWindowSize = () => {
      if (
        !examState.examStarted ||
        !document.fullscreenElement ||
        examState.examEnded ||
        examState.isSubmitting ||
        examState.proctoringStatus?.isPaused
      )
        return
      const ratio = window.outerHeight / window.screen.height
      if (ratio < 0.95) {
        proctoringEngine.pauseExam(
          'Window was minimized or resized. Return to fullscreen to resume.'
        )
      }
    }
    const interval = setInterval(checkWindowSize, 2000)
    return () => clearInterval(interval)
  }, [
    examState.examStarted,
    examState.examEnded,
    examState.isSubmitting,
    examState.proctoringStatus?.isPaused,
  ])

  // Safety net: Stop camera on page unload + warn user
  useEffect(() => {
    const handleBeforeUnload = (e: BeforeUnloadEvent) => {
      if (examState.examStarted && !examState.examEnded) {
        e.preventDefault()
        e.returnValue = 'Exam in progress! Leaving will forfeit your answers.'
        return e.returnValue
      }
      stopCamera()
    }
    window.addEventListener('beforeunload', handleBeforeUnload)
    return () => window.removeEventListener('beforeunload', handleBeforeUnload)
  }, [stopCamera, examState.examStarted, examState.examEnded])

  // Enter fullscreen
  const enterFullscreen = async () => {
    if (document.fullscreenElement) {
      dispatch({ type: 'SET_FULLSCREEN', payload: true })
      return
    }
    try {
      const target = document.documentElement as HTMLElement & {
        webkitRequestFullscreen?: () => Promise<void>
        msRequestFullscreen?: () => Promise<void>
      }
      if (target.requestFullscreen) {
        await target.requestFullscreen({ navigationUI: 'hide' } as FullscreenOptions)
      } else if (target.webkitRequestFullscreen) {
        await target.webkitRequestFullscreen()
      } else if (target.msRequestFullscreen) {
        await target.msRequestFullscreen()
      }
      dispatch({ type: 'SET_FULLSCREEN', payload: true })
    } catch (error) {
      console.error('Fullscreen failed:', error)
    }
  }

  const startCamera = async () => {
    dispatch({ type: 'SET_INITIALIZING_CAMERA', payload: true })
    setInitMessage('Initializing camera...')

    // ΓöÇΓöÇ PHASE 1: Attach stream to video element immediately ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
    try {
      const preExamStream = (window as any).__preExamStream as MediaStream | undefined
      let stream: MediaStream

      if (preExamStream && preExamStream.active) {
        stream = preExamStream
        delete (window as any).__preExamStream
        console.log('[Camera] Reusing pre-exam stream')
      } else {
        stream = await navigator.mediaDevices.getUserMedia({
          video: { width: { ideal: 1280 }, height: { ideal: 720 }, facingMode: 'user' },
          audio: { echoCancellation: false, noiseSuppression: false, autoGainControl: false },
        })
      }

      if (videoRef.current) {
        if (videoRef.current.srcObject && videoRef.current.srcObject !== stream) {
          ;(videoRef.current.srcObject as MediaStream).getTracks().forEach(t => t.stop())
        }
        videoRef.current.srcObject = stream
        videoRef.current.muted = true
        videoRef.current.playsInline = true
        videoRef.current.play().catch(e => console.warn('[Camera] play():', e))
      }

      dispatch({ type: 'ENABLE_CAMERA', payload: true })
      dispatch({ type: 'ENABLE_MIC', payload: true })
      dispatch({ type: 'SET_INITIALIZING_CAMERA', payload: false })

      // Initialize WebSocket for teacher monitoring
      if (user) {
        try {
          const testIdValue = testId || 'practice'
          const wsClient = new WebSocketClient()
          wsClientRef.current = wsClient
          const userId = user._id || user.email || 'unknown'
          wsClient.connect({ userId, role: 'student', examId: testIdValue })

          // Heartbeat
          heartbeatRef.current = window.setInterval(() => {
            if (wsClient.isConnected()) {
              wsClient.send({
                type: 'heartbeat',
                exam_id: testIdValue,
                student_id: userId,
                timestamp: new Date().toISOString(),
              })
            }
          }, 10000)

          // Trust score sync
          trustSyncRef.current = window.setInterval(() => {
            if (wsClient.isConnected()) {
              wsClient.send({
                type: 'proctoring_status',
                exam_id: testIdValue,
                student_id: userId,
                trust_score: 100,
                status: { isActive: true },
              })
            }
          }, 30000)

          wsClient.on('intervention', (data: any) => {
            const action = data.action as string
            if (action === 'pause') {
              setExamPaused(true)
              proctoringEngine.pauseExam('Exam paused by teacher. Please wait.')
            } else if (action === 'resume') {
              setExamPaused(false)
              proctoringEngine.resumeExam()
              if (examState.proctoringStatus) {
                dispatch({
                  type: 'SET_PROCTORING_STATUS',
                  payload: { ...examState.proctoringStatus, isPaused: false } as ProctoringStatus,
                })
              }
            }
          })
        } catch (wsErr) {
          console.warn('[WebSocket] Connection failed:', wsErr)
        }
      }
    } catch (streamErr) {
      const msg = streamErr instanceof Error ? streamErr.message : String(streamErr)
      if (msg.includes('NotAllowedError') || msg.includes('Permission')) {
        alert('Camera permission denied. Please allow camera access and refresh.')
      } else if (msg.includes('NotFoundError')) {
        alert('No camera found. Please connect a camera.')
      }
      dispatch({ type: 'ENABLE_CAMERA', payload: false })
      dispatch({ type: 'ENABLE_MIC', payload: false })
      dispatch({ type: 'SET_INITIALIZING_CAMERA', payload: false })
      return
    }

    // ΓöÇΓöÇ PHASE 2: Initialize AI engine with the already-playing stream ΓöÇΓöÇ
    setInitMessage('Loading AI proctoring engine...')
    setTimeout(async () => {
      const stream = videoRef.current?.srcObject as MediaStream | null
      if (!stream || !stream.active || !videoRef.current) return

      try {
        await proctoringEngine.loadModels()
        await proctoringEngine.initialize(videoRef.current!, stream)

        proctoringEngine.setOnViolation(violation => {
          dispatch({ type: 'ADD_ACTIVE_VIOLATION', payload: violation })
          setTimeout(() => {
            dispatch({ type: 'REMOVE_ACTIVE_VIOLATION', payload: violation })
          }, 5000)
          dispatch({ type: 'ADD_VIOLATION', payload: violation.message })
          // Show toast for audio and other violations
          if (violation.type === 'AUDIO_DETECTED') {
            alert(
              `≡ƒöè Audio Warning: ${violation.message}\n\nPlease ensure a quiet environment for the exam.`
            )
          } else if (violation.type === 'HEADPHONE_DETECTED') {
            alert(
              `≡ƒÄº Headphone Warning: ${violation.message}\n\nPlease remove headphones during the exam.`
            )
          } else if (violation.severity === 'HIGH' || violation.severity === 'CRITICAL') {
            alert(`ΓÜá∩╕Å ${violation.message}`)
          }
        })

        proctoringEngine.setOnStatusChange(status => {
          dispatch({ type: 'SET_PROCTORING_STATUS', payload: status })
          dispatch({ type: 'SET_TAB_SWITCHES', payload: status.tabSwitchCount })
        })

        proctoringEngine.setOnPause(reason => {
          alert('Exam paused: ' + reason)
        })

        setTimeout(async () => {
          const faceCapture = await proctoringEngine.captureReferenceFace()
          if (faceCapture) {
            console.log('Reference face captured for identity verification')
          } else {
            console.warn('Reference face capture failed - continuing')
          }
        }, 3000)

        proctoringEngine.enableRecording()
        proctoringEngine.startMonitoring()
      } catch (engineErr) {
        console.warn('[Proctoring] AI engine initialization failed:', engineErr)
      }
    }, 500)
  }

  const handleStartExam = async (isAutoStart = false) => {
    if (!examState.cameraEnabled || !examState.micEnabled) {
      if (isAutoStart) {
        console.warn('[AutoStart] Camera/mic not ready, deferring')
        return
      }
      alert(
        'ΓÜá∩╕Å CAMERA AND MICROPHONE REQUIRED\n\n' +
          'You must enable camera and microphone before starting the exam.\n\n' +
          'If camera failed to enable, it may be due to:\n' +
          'Γ£à Insufficient lighting - Turn on lights\n' +
          'Γ£à No camera permission - Allow camera access\n' +
          'Γ£à Camera already in use - Close other apps\n\n' +
          'Please fix the issue and click "Enable Camera" again.'
      )
      return
    }

    // Brightness check: warn during auto-start, block during manual
    const currentBrightness = proctoringEngine.getBrightness()
    if (currentBrightness < 50) {
      if (isAutoStart) {
        console.warn(
          `[AutoStart] Low brightness (${Math.round(currentBrightness)}/255), starting anyway`
        )
      } else {
        alert(
          `≡ƒÜ¿ CANNOT START EXAM\n\n` +
            `Room lighting is too low: ${Math.round(currentBrightness)}/255\n` +
            `Minimum required: 50/255\n\n` +
            `Γ£à Turn on lights immediately\n` +
            `Γ£à Ensure your face is well-lit\n` +
            `Γ£à Sit near a window or lamp\n\n` +
            `Exam cannot start until lighting improves.\n` +
            `This is mandatory to prevent cheating.`
        )
        return
      }
    }

    // For auto-start: fullscreen should already be set from pre-verification
    // For manual start: user gesture is available, so fullscreen will work
    if (!isAutoStart) {
      await enterFullscreen()
    } else if (!document.fullscreenElement) {
      // Auto-start but not in fullscreen ΓÇö don't proceed
      console.warn('[AutoStart] Not in fullscreen, deferring to manual start')
      return
    }

    dispatch({ type: 'START_EXAM' })
  }

  const handleAnswerChange = (questionId: number, answer: any) => {
    const previousAnswer = examState.answers[questionId]
    const isChangingAnswer = previousAnswer !== undefined

    // Update answer in state
    dispatch({ type: 'SET_ANSWER', payload: { questionId, answer } })

    // Only process for adaptive logic if this is the first time answering (not changing answer)
    if (!isChangingAnswer) {
      const question = mockTestData.questions[questionId]
      const isCorrect = checkAnswer(question, answer)

      // Update adaptive engine
      adaptiveEngine.processAnswer(isCorrect, question.difficulty as DifficultyLevel)

      // Update current difficulty
      const newDifficulty = adaptiveEngine.getCurrentDifficulty()
      if (newDifficulty !== examState.currentDifficulty) {
        dispatch({ type: 'SET_DIFFICULTY', payload: newDifficulty })
        dispatch({ type: 'ADD_DIFFICULTY_HISTORY', payload: newDifficulty })
      }
    }
  }

  // Helper function to check if answer is correct
  const checkAnswer = (question: Question, userAnswer: any): boolean => {
    if (!userAnswer) return false

    if (question.type === 'multiple-answer') {
      if (!Array.isArray(userAnswer) || !Array.isArray(question.correctAnswer)) return false
      if (userAnswer.length !== question.correctAnswer.length) return false
      return (
        JSON.stringify([...userAnswer].sort()) ===
        JSON.stringify([...question.correctAnswer].sort())
      )
    }

    // Handle string comparison (case-insensitive for short-answer)
    if (question.type === 'short-answer') {
      return (
        String(userAnswer).trim().toLowerCase() ===
        String(question.correctAnswer).trim().toLowerCase()
      )
    }

    return userAnswer === question.correctAnswer
  }

  const handleFlagQuestion = () => {
    dispatch({ type: 'TOGGLE_FLAG', payload: examState.currentQuestion })
  }

  const handleSubmitExam = async () => {
    // Prevent duplicate submissions
    if (examState.isSubmitting || examState.examEnded) {
      console.log('ΓÜá∩╕Å Already submitting or exam ended, ignoring...')
      return
    }

    // Set submitting flag BEFORE any dialogs or actions
    dispatch({ type: 'SET_SUBMITTING', payload: true })

    // Small delay to let state update propagate
    await new Promise(resolve => setTimeout(resolve, 100))

    // Check if auto-submit (time expired) or manual submit
    const isAutoSubmit = examState.timeRemaining === 0
    const shouldSubmit = isAutoSubmit || window.confirm('Are you sure you want to submit the exam?')

    if (shouldSubmit) {
      console.log('≡ƒ¢æ Stopping camera and monitoring before submission...')
      await stopCamera()
      dispatch({ type: 'END_EXAM' })
      calculateResults()
    } else {
      // User cancelled - reset submitting flag
      dispatch({ type: 'SET_SUBMITTING', payload: false })
    }
  }

  const calculateResults = () => {
    let correctAnswers = 0
    let totalPoints = 0
    let earnedPoints = 0

    // Prepare data for weak area analysis
    const answerData: Array<{
      category: string
      difficulty: DifficultyLevel
      isCorrect: boolean
    }> = []

    mockTestData.questions.forEach((question, index) => {
      totalPoints += question.points
      const userAnswer = examState.answers[index]
      let isCorrect = false

      if (question.type === 'multiple-answer') {
        isCorrect = Array.isArray(question.correctAnswer)
          ? JSON.stringify(userAnswer?.sort()) === JSON.stringify(question.correctAnswer.sort())
          : false
        if (isCorrect) {
          correctAnswers++
          earnedPoints += question.points
        }
      } else {
        isCorrect = userAnswer === question.correctAnswer
        if (isCorrect) {
          correctAnswers++
          earnedPoints += question.points
        }
      }

      // Collect data for adaptive analysis
      answerData.push({
        category: mockTestData.category,
        difficulty: question.difficulty as DifficultyLevel,
        isCorrect,
      })
    })

    const percentage = Math.round((earnedPoints / totalPoints) * 100)

    // Analyze weak areas and generate learning path
    const weakAreas = adaptiveEngine.analyzeWeakAreas(answerData)
    const learningPath = adaptiveEngine.generateLearningPath(weakAreas)
    const performanceMetrics = adaptiveEngine.getMetrics()
    const performanceTrend = adaptiveEngine.getPerformanceTrend()

    console.log('≡ƒÜÇ Step 5: Navigating to results (camera confirmed stopped)...')

    // NOW navigate - camera is guaranteed stopped
    navigate('/practice/results', {
      state: {
        testId: mockTestData.id,
        testTitle: mockTestData.title,
        totalQuestions: mockTestData.questions.length,
        correctAnswers,
        percentage,
        violations: examState.violations,
        tabSwitches: examState.tabSwitches,
        timeTaken: mockTestData.duration * 60 - examState.timeRemaining,
        // Adaptive exam data
        weakAreas,
        learningPath,
        performanceMetrics,
        performanceTrend,
        difficultyHistory: examState.difficultyHistory,
        // Question review data
        questions: mockTestData.questions,
        userAnswers: examState.answers,
      },
    })

    console.log('Γ£à ========== EXAM SUBMISSION COMPLETE ==========')
  }

  const formatTime = (seconds: number) => {
    const totalSeconds = Math.max(0, Math.floor(seconds))
    const mins = Math.floor(totalSeconds / 60)
    const secs = totalSeconds % 60
    return `${mins}:${secs.toString().padStart(2, '0')}`
  }

  const getAnsweredCount = () => Object.keys(examState.answers).length
  const getQuestionStatus = (index: number) => {
    if (examState.answers[index] !== undefined) return 'answered'
    if (examState.flaggedQuestions.has(index)) return 'flagged'
    return 'unanswered'
  }

  if (!examState.examStarted) {
    return (
      <div className="min-h-screen bg-gray-950 flex items-center justify-center">
        <div className="text-center max-w-md mx-auto px-6">
          {/* Logo */}
          <div className="w-16 h-16 bg-gradient-to-br from-blue-500 to-purple-600 rounded-2xl flex items-center justify-center mx-auto mb-6 shadow-lg shadow-blue-500/30">
            <Brain className="w-8 h-8 text-white" />
          </div>

          {/* Title */}
          <h1 className="text-2xl font-bold text-white mb-2">{mockTestData.title}</h1>
          <p className="text-gray-400 text-sm mb-8">AI-Proctored Mock Test</p>

          {/* Spinner + Status */}
          {examState.isInitializingCamera && (
            <>
              <div className="animate-spin w-12 h-12 border-4 border-blue-500 border-t-transparent rounded-full mx-auto mb-4"></div>
              <p className="text-blue-400 font-medium text-sm">{initMessage}</p>
              <p className="text-gray-600 text-xs mt-2">This may take a few seconds</p>
            </>
          )}

          {/* Camera preview (hidden but accessible for ref) */}
          <div
            className={`mt-6 bg-gray-900 rounded-xl overflow-hidden ${examState.cameraEnabled ? 'w-48 h-36 mx-auto' : 'sr-only h-0'}`}
          >
            <video
              ref={videoRef}
              autoPlay
              playsInline
              muted
              className="w-full h-full object-cover"
            />
          </div>

          {/* Error: camera failed */}
          {!examState.isInitializingCamera && !examState.cameraEnabled && (
            <div className="mt-4">
              <div className="bg-red-900/30 border border-red-500/30 rounded-xl p-4 mb-4">
                <p className="text-red-400 font-medium text-sm">Camera initialization failed</p>
                <p className="text-red-300 text-xs mt-1">
                  Please check camera permissions and try again
                </p>
              </div>
              <button
                onClick={() => startCamera()}
                className="px-6 py-3 bg-blue-600 text-white rounded-xl font-medium hover:bg-blue-700 transition"
              >
                Retry Camera
              </button>
              <button
                onClick={() => navigate('/practice')}
                className="px-6 py-3 mt-2 bg-gray-800 text-gray-300 rounded-xl font-medium hover:bg-gray-700 transition block w-full"
              >
                Cancel
              </button>
            </div>
          )}
        </div>
      </div>
    )
  }

  const question = mockTestData.questions[examState.currentQuestion]

  // Safety check - redirect if invalid question index
  if (!question && examState.examStarted) {
    console.error('Invalid question index:', examState.currentQuestion)
    navigate('/practice')
    return null
  }

  return (
    <div className="min-h-screen bg-gray-50 flex flex-col">
      {/* Violation Warnings */}
      <AnimatePresence>
        {examState.activeViolations.map((violation, index) => (
          <div
            key={`${violation.timestamp.getTime()}-${index}`}
            style={{ top: `${4 + index * 120}px` }}
          >
            <ViolationWarning
              violation={violation}
              onDismiss={() => dispatch({ type: 'REMOVE_ACTIVE_VIOLATION', payload: violation })}
            />
          </div>
        ))}
      </AnimatePresence>

      {/* Violation Summary */}
      {examState.proctoringStatus && (
        <ViolationSummary violations={examState.proctoringStatus.violations} />
      )}

      {/* Proctoring Status Bar */}
      {examState.proctoringStatus && !examState.examEnded && (
        <ProctoringStatusBar
          faceDetected={examState.proctoringStatus.faceDetected}
          faceCount={examState.proctoringStatus.faceCount}
          lookingAtScreen={examState.proctoringStatus.lookingAtScreen}
          audioLevel={examState.proctoringStatus.audioLevel}
          isFullscreen={examState.isFullscreen}
          brightness={examState.proctoringStatus.brightness ?? examState.brightness}
          attentionLevel={examState.proctoringStatus.attentionLevel}
          integrityScore={examState.proctoringStatus.integrityScore}
        />
      )}

      {/* Fullscreen Warning */}
      {!examState.isFullscreen && (
        <div className="fixed top-4 left-1/2 transform -translate-x-1/2 bg-red-600 text-white px-6 py-3 rounded-full shadow-2xl z-50 flex items-center gap-2 animate-pulse">
          <Maximize className="w-5 h-5" />
          <span className="font-bold">Please return to fullscreen mode!</span>
          <button
            onClick={enterFullscreen}
            className="ml-2 bg-white text-red-600 px-3 py-1 rounded-full text-sm font-bold hover:bg-gray-100"
          >
            Enter Fullscreen
          </button>
        </div>
      )}

      {/* Time's Up Overlay */}
      {showTimesUp && (
        <div className="fixed inset-0 bg-gradient-to-br from-yellow-500/90 to-red-500/90 backdrop-blur-sm z-50 flex items-center justify-center">
          <div className="bg-white rounded-2xl p-8 max-w-md w-full mx-4 shadow-2xl text-center animate-bounce">
            <div className="w-20 h-20 bg-gradient-to-br from-yellow-400 to-red-500 rounded-full flex items-center justify-center mx-auto mb-4">
              <Clock className="w-10 h-10 text-white" />
            </div>
            <h2 className="text-3xl font-bold text-gray-900 mb-2">ΓÅ░ Time's Up!</h2>
            <p className="text-gray-600 text-lg mb-2">Your exam time has expired.</p>
            <p className="text-gray-500 text-sm">Auto-submitting your answers...</p>
            <div className="mt-6 w-full bg-gray-200 rounded-full h-2 overflow-hidden">
              <div
                className="bg-gradient-to-r from-yellow-400 to-red-500 h-2 rounded-full animate-pulse"
                style={{ width: '100%' }}
              />
            </div>
          </div>
        </div>
      )}

      {/* Submitting Overlay */}
      {examState.isSubmitting && (
        <div className="fixed inset-0 bg-black/80 backdrop-blur-sm z-50 flex items-center justify-center">
          <div className="bg-white rounded-2xl p-8 max-w-md w-full mx-4 shadow-2xl text-center">
            <div className="animate-spin w-16 h-16 border-4 border-blue-600 border-t-transparent rounded-full mx-auto mb-4"></div>
            <h2 className="text-2xl font-bold text-gray-900 mb-2">Submitting Exam...</h2>
            <p className="text-gray-600">
              Please wait while we process your answers and stop the camera.
            </p>
          </div>
        </div>
      )}

      {/* Exam Paused Overlay */}
      {examState.proctoringStatus?.isPaused && (
        <motion.div
          initial={{ opacity: 0 }}
          animate={{ opacity: 1 }}
          className="fixed inset-0 bg-black/80 backdrop-blur-sm z-50 flex items-center justify-center"
        >
          <motion.div
            initial={{ scale: 0.9, y: 20 }}
            animate={{ scale: 1, y: 0 }}
            className="bg-white rounded-2xl p-8 max-w-md w-full mx-4 shadow-2xl"
          >
            <div className="text-center">
              <div className="w-20 h-20 bg-red-100 rounded-full flex items-center justify-center mx-auto mb-4">
                <AlertTriangle className="w-10 h-10 text-red-600" />
              </div>
              <h2 className="text-2xl font-bold text-gray-900 mb-2">Exam Paused</h2>
              <p className="text-gray-600 mb-6">{examState.proctoringStatus.pauseReason}</p>

              <div className="bg-yellow-50 border border-yellow-200 rounded-lg p-4 mb-6">
                <p className="text-sm text-yellow-800">
                  <strong>Suspicious Activity Score:</strong>{' '}
                  {examState.proctoringStatus.suspiciousActivityScore}/100
                </p>
                <p className="text-xs text-yellow-600 mt-2">
                  Multiple critical examState.violations detected. Please contact the proctor to
                  resume.
                </p>
              </div>

              <button
                onClick={() => {
                  if (
                    window.confirm(
                      "Are you sure you want to resume? Make sure you're in fullscreen with only the exam tab open."
                    )
                  ) {
                    proctoringEngine.resumeExam()
                    if (examState.proctoringStatus) {
                      dispatch({
                        type: 'SET_PROCTORING_STATUS',
                        payload: {
                          ...examState.proctoringStatus,
                          isPaused: false,
                        } as ProctoringStatus,
                      })
                    }
                    const target = document.documentElement as HTMLElement & {
                      webkitRequestFullscreen?: () => Promise<void>
                      msRequestFullscreen?: () => Promise<void>
                    }
                    if (target.requestFullscreen) {
                      target
                        .requestFullscreen({ navigationUI: 'hide' } as FullscreenOptions)
                        .catch(() => {})
                    } else if (target.webkitRequestFullscreen) {
                      target.webkitRequestFullscreen().catch(() => {})
                    } else if (target.msRequestFullscreen) {
                      target.msRequestFullscreen().catch(() => {})
                    }
                  }
                }}
                className="w-full bg-gradient-to-r from-blue-600 to-indigo-600 text-white py-3 rounded-lg font-semibold hover:from-blue-700 hover:to-indigo-700 transition-all"
              >
                Resume Exam
              </button>
            </div>
          </motion.div>
        </motion.div>
      )}

      {/* Header */}
      <header className="bg-gradient-to-r from-blue-600 to-indigo-600 text-white shadow-lg sticky top-0 z-40">
        <div className="max-w-full px-3 sm:px-4 py-3 sm:py-4">
          <div className="flex items-center justify-between">
            <div className="flex items-center space-x-2 sm:space-x-3">
              <button
                onClick={() => dispatch({ type: 'TOGGLE_MOBILE_MENU' })}
                className="lg:hidden p-2 hover:bg-white/10 rounded-lg min-h-[44px] min-w-[44px] touch-manipulation"
              >
                <Menu className="w-5 h-5" />
              </button>
              <Brain className="w-6 h-6 sm:w-8 sm:h-8" />
              <div>
                <h1 className="text-sm sm:text-base font-bold truncate max-w-[200px] sm:max-w-none">
                  {mockTestData.title}
                </h1>
                <p className="text-xs text-blue-100 hidden sm:block">
                  Question {examState.currentQuestion + 1} of {mockTestData.questions.length}
                </p>
              </div>
            </div>

            <div className="flex items-center space-x-2 sm:space-x-4">
              <div
                className={`flex items-center space-x-2 px-3 py-2 rounded-lg ${
                  examState.timeRemaining < 300 ? 'bg-red-500' : 'bg-white/20'
                } min-h-[44px]`}
              >
                <Clock className="w-4 h-4 sm:w-5 sm:h-5" />
                <span className="font-bold text-sm sm:text-base">
                  {formatTime(examState.timeRemaining)}
                </span>
              </div>
              {!isMobile && (
                <div className="flex items-center space-x-1 bg-white/20 px-3 py-2 rounded-lg">
                  <Eye className="w-4 h-4" />
                  <span className="text-sm">AI Monitoring</span>
                </div>
              )}
            </div>
          </div>
        </div>
      </header>

      <div className="flex flex-1 overflow-hidden">
