      category: 'mathematics',
      difficulty: 'Hard',
      count: 50,
      duration: 90,
      title: 'Mathematics - Advanced Calculus',
    },

    // Science Tests
    'mock-sci-1': {
      category: 'science',
      difficulty: 'Easy',
      count: 35,
      duration: 50,
      title: 'Science - Physics Fundamentals',
    },
    'mock-sci-2': {
      category: 'science',
      difficulty: 'Medium',
      count: 40,
      duration: 60,
      title: 'Science - Chemistry & Biology',
    },
    'mock-sci-3': {
      category: 'science',
      difficulty: 'Hard',
      count: 45,
      duration: 75,
      title: 'Science - Advanced Physics',
    },

    // General Knowledge Tests
    'mock-gk-1': {
      category: 'general-knowledge',
      difficulty: 'Easy',
      count: 50,
      duration: 40,
      title: 'GK - Current Affairs 2024-25',
    },
    'mock-gk-2': {
      category: 'general-knowledge',
      difficulty: 'Medium',
      count: 60,
      duration: 50,
      title: 'GK - World Geography & Politics',
    },
    'mock-gk-3': {
      category: 'general-knowledge',
      difficulty: 'Hard',
      count: 100,
      duration: 90,
      title: 'GK - Comprehensive Test',
    },

    // History Tests
    'mock-hist-1': {
      category: 'history',
      difficulty: 'Easy',
      count: 30,
      duration: 40,
      title: 'History - Ancient Civilizations',
    },
    'mock-hist-2': {
      category: 'history',
      difficulty: 'Medium',
      count: 35,
      duration: 50,
      title: 'History - Indian Independence',
    },
    'mock-hist-3': {
      category: 'history',
      difficulty: 'Hard',
      count: 40,
      duration: 60,
      title: 'History - World Wars & Modern Era',
    },

    // English Tests
    'mock-eng-1': {
      category: 'english',
      difficulty: 'Easy',
      count: 25,
      duration: 30,
      title: 'English - Grammar Basics',
    },
    'mock-eng-2': {
      category: 'english',
      difficulty: 'Medium',
      count: 35,
      duration: 45,
      title: 'English - Vocabulary & Comprehension',
    },
    'mock-eng-3': {
      category: 'english',
      difficulty: 'Hard',
      count: 40,
      duration: 60,
      title: 'English - Advanced Literature',
    },

    // Reasoning Tests
    'mock-reas-1': {
      category: 'reasoning',
      difficulty: 'Easy',
      count: 30,
      duration: 40,
      title: 'Reasoning - Basic Puzzles',
    },
    'mock-reas-2': {
      category: 'reasoning',
      difficulty: 'Medium',
      count: 35,
      duration: 50,
      title: 'Reasoning - Analytical Thinking',
    },
    'mock-reas-3': {
      category: 'reasoning',
      difficulty: 'Hard',
      count: 40,
      duration: 60,
      title: 'Reasoning - Complex Problems',
    },
  }

  const config = testConfigs[testId]

  if (config) {
    // Get questions from question bank
    const bankQuestions = getQuestionsByCategory(config.category, config.difficulty, config.count)

    // If not enough questions in bank, supplement with generated ones
    const questions: Question[] = bankQuestions.map(q => ({
      id: q.id,
      text: q.text,
      type: q.type,
      options: q.options,
      correctAnswer: q.correctAnswer,
      points: q.points,
      explanation: q.explanation,
      difficulty: q.difficulty,
    }))

    // Generate additional questions if needed
    if (questions.length < config.count) {
      const additionalCount = config.count - questions.length
      const generated = generateCategoryQuestions(
        config.category,
        additionalCount,
        questions.length + 1
      )
      questions.push(...generated)
    }

    return {
      id: testId,
      title: config.title,
      category: config.category,
      duration: config.duration,
      passingScore: 60,
      questions: questions.slice(0, config.count),
    }
  }

  // Default fallback
  return {
    id: testId,
    title: 'Practice Test',
    category: 'general',
    duration: 60,
    passingScore: 60,
    questions: generateGenericQuestions(30),
  }
}

// Generate category-specific questions when bank doesn't have enough
function generateCategoryQuestions(category: string, count: number, startId: number): Question[] {
  const questions: Question[] = []
  const templates = getCategoryTemplates(category)

  for (let i = 0; i < count; i++) {
    const template = templates[i % templates.length]
    questions.push({
      id: startId + i,
      text: template.text || 'Sample question',
      type: template.type || 'mcq',
      options: template.options,
      correctAnswer: template.correctAnswer || 'Option A',
      points: 2,
      explanation: template.explanation || 'Sample explanation',
      difficulty: template.difficulty || 'Medium',
    })
  }
  return questions
}

