                                    <div
                                      key={bar}
                                      className="w-1 rounded-sm transition-all"
                                      style={{
                                        height: `${bar * 4}px`,
                                        backgroundColor:
                                          (session.audio_level || 0) > 75
                                            ? '#ef4444' // red ΓÇö loud/suspicious
                                            : (session.audio_level || 0) > bar * 25
                                              ? '#10b981'
                                              : '#374151',
                                      }}
                                    />
                                  ))}
                                </div>
                              </div>
                            )}

                            {/* Trust Score */}
                            <div className="text-center">
                              <div
                                className={`text-sm font-black ${
