                                className="px-2 py-1 bg-orange-950/60 border border-orange-700/50 text-orange-400 text-[10px] font-bold rounded hover:bg-orange-900/70 transition"
                              >
                                ΓÅ╕
                              </button>
                              {session.is_paused && (
                                <button
                                  onClick={() =>
                                    handleIntervene(
                                      session.student_id,
                                      'resume',
