          </div>

          {/* Right Panel - Violations & Analytics */}
          <div className="space-y-4">
            {/* Real-time Violation Feed */}
            <div className="bg-gray-900/80 rounded-xl border border-gray-800 backdrop-blur">
              <div className="px-5 py-4 border-b border-gray-800 flex items-center justify-between">
                <div className="flex items-center gap-2">
                  <AlertTriangle className="w-4 h-4 text-red-400" />
                  <h3 className="font-bold text-gray-200">Violation Feed</h3>
                </div>
                <span className="text-xs text-gray-500">{flags.length} total</span>
              </div>

              <div className="max-h-64 overflow-y-auto">
                {flags.length === 0 ? (
                  <div className="text-center py-8">
                    <CheckCircle className="w-10 h-10 text-emerald-600/40 mx-auto mb-2" />
                    <p className="text-gray-600 text-sm">No violations recorded</p>
                  </div>
                ) : (
                  <div className="p-3 space-y-2">
                    {[...flags]
                      .reverse()
                      .slice(0, 20)
                      .map((flag, idx) => {
                        const student = sessions.find(s => s.student_id === flag.student_id)
                        const isCritical = ['CRITICAL', 'critical'].includes(flag.severity)
                        return (
                          <motion.div
                            key={idx}
                            initial={{ opacity: 0, y: -5 }}
                            animate={{ opacity: 1, y: 0 }}
                            className={`border rounded-lg p-2.5 text-xs ${
                              isCritical
                                ? 'border-red-800/50 bg-red-950/20'
                                : 'border-orange-800/30 bg-orange-950/10'
                            }`}
                          >
                            <div className="flex items-center justify-between gap-2 mb-1">
                              <span className="font-semibold text-white truncate">
                                {student?.student_name || 'Unknown'}
                              </span>
                              <span
                                className={`px-1.5 py-0.5 rounded text-[10px] font-bold border ${
                                  isCritical
                                    ? 'bg-red-950 text-red-400 border-red-700'
                                    : 'bg-orange-950 text-orange-400 border-orange-700'
                                }`}
                              >
                                {flag.severity.toUpperCase()}
                              </span>
                            </div>
                            <p
                              className={`font-medium ${isCritical ? 'text-red-400' : 'text-orange-400'}`}
                            >
                              {(flag.flag_type || flag.type || '').replace(/_/g, ' ')}
                            </p>
                            <p className="text-gray-500 mt-0.5 truncate">
                              {flag.evidence || flag.message || ''}
                            </p>
                            <p className="text-gray-600 mt-1">
                              {new Date(flag.timestamp).toLocaleTimeString()}
                            </p>
                          </motion.div>
                        )
                      })}
                  </div>
                )}
              </div>
            </div>

            {/* Class Analytics */}
            <div className="bg-gray-900/80 rounded-xl border border-gray-800 p-5 backdrop-blur">
              <div className="flex items-center gap-2 mb-4">
                <BarChart3 className="w-4 h-4 text-purple-400" />
                <h3 className="font-bold text-gray-200">Class Analytics</h3>
              </div>

              <div className="space-y-3">
                {/* Trust Score Distribution */}
                <div>
                  <div className="flex justify-between text-xs text-gray-500 mb-1.5">
                    <span>Trust Score Distribution</span>
                    <span>{stats.avgTrustScore}% avg</span>
                  </div>
                  <div className="h-2 bg-gray-800 rounded-full overflow-hidden flex">
                    {sessions.length > 0 && (
                      <>
                        <div
                          className="h-full bg-emerald-500 transition-all"
                          style={{
                            width: `${(sessions.filter(s => s.trust_score >= 80).length / sessions.length) * 100}%`,
                          }}
                          title="High trust (80%+)"
                        />
                        <div
                          className="h-full bg-yellow-500 transition-all"
                          style={{
                            width: `${(sessions.filter(s => s.trust_score >= 60 && s.trust_score < 80).length / sessions.length) * 100}%`,
                          }}
                          title="Medium trust (60-79%)"
                        />
                        <div
                          className="h-full bg-red-500 transition-all"
                          style={{
                            width: `${(sessions.filter(s => s.trust_score < 60).length / sessions.length) * 100}%`,
                          }}
                          title="Low trust (<60%)"
                        />
                      </>
                    )}
                  </div>
                  <div className="flex gap-3 mt-1.5 text-[10px]">
                    <span className="text-emerald-400">ΓùÅ High</span>
                    <span className="text-yellow-400">ΓùÅ Medium</span>
                    <span className="text-red-400">ΓùÅ Low</span>
                  </div>
                </div>

                {/* Violation Types */}
                {flags.length > 0 && (
                  <div>
                    <div className="text-xs text-gray-500 mb-2">Top Violation Types</div>
                    {Object.entries(
                      flags.reduce(
                        (acc, f) => {
                          const t = (f.flag_type || f.type || 'unknown').replace(/_/g, ' ')
                          acc[t] = (acc[t] || 0) + 1
                          return acc
                        },
                        {} as Record<string, number>
                      )
                    )
                      .sort((a, b) => b[1] - a[1])
                      .slice(0, 4)
                      .map(([type, count]) => (
                        <div key={type} className="flex items-center gap-2 mb-1.5">
                          <div className="flex-1">
                            <div className="flex justify-between text-xs mb-0.5">
                              <span className="text-gray-400 capitalize truncate">{type}</span>
                              <span className="text-gray-500">{count}</span>
                            </div>
                            <div className="h-1.5 bg-gray-800 rounded-full overflow-hidden">
                              <div
                                className="h-full bg-orange-500/70 rounded-full"
                                style={{ width: `${(count / flags.length) * 100}%` }}
                              />
                            </div>
                          </div>
                        </div>
                      ))}
                  </div>
                )}
              </div>
            </div>

            {/* Quick Intervention */}
            {selectedStudent && selectedStudentData && (
              <div className="bg-gray-900/80 rounded-xl border border-yellow-800/40 p-5 backdrop-blur">
                <div className="flex items-center justify-between mb-3">
                  <h3 className="font-bold text-yellow-400 flex items-center gap-2">
                    <MessageSquare className="w-4 h-4" />
                    Quick Action
                  </h3>
                  <span className="text-xs text-gray-400">{selectedStudentData.student_name}</span>
                </div>
                <div className="flex gap-2">
                  <button
                    onClick={() =>
                      handleIntervene(
                        selectedStudent,
                        'warn',
                        'Please follow exam rules. This is an official warning.'
                      )
                    }
                    className="flex-1 py-2 px-3 bg-yellow-950/50 border border-yellow-800/50 text-yellow-400 rounded-lg text-xs font-semibold hover:bg-yellow-900/50 transition"
                  >
                    ΓÜá Warn
                  </button>
                  {selectedStudentData?.is_paused ? (
                    <button
                      onClick={() =>
                        handleIntervene(
                          selectedStudent,
                          'resume',
                          'Your exam has been resumed by the proctor.'
                        )
                      }
                      className="flex-1 py-2 px-3 bg-green-950/50 border border-green-800/50 text-green-400 rounded-lg text-xs font-semibold hover:bg-green-900/50 transition"
                    >
                      Γû╢ Resume
                    </button>
                  ) : (
                    <button
                      onClick={() =>
                        handleIntervene(
                          selectedStudent,
                          'pause',
                          'Your exam has been paused by the proctor for review.'
                        )
                      }
                      className="flex-1 py-2 px-3 bg-orange-950/50 border border-orange-800/50 text-orange-400 rounded-lg text-xs font-semibold hover:bg-orange-900/50 transition"
                    >
                      ΓÅ╕ Pause
                    </button>
                  )}
                  <button
                    onClick={() => setShowStudentModal(true)}
                    className="flex-1 py-2 px-3 bg-blue-950/50 border border-blue-800/50 text-blue-400 rounded-lg text-xs font-semibold hover:bg-blue-900/50 transition"
                  >
                    ≡ƒöì Details
                  </button>
                </div>
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  )
}

import { useState, useEffect } from 'react'
import {
  Database,
  Plus,
  Search,
  Upload,
  Download,
  Edit,
  Trash2,
  Copy,
  Eye,
  Star,
  BookOpen,
  Tag,
  X,
  Save,
  Loader2,
} from 'lucide-react'
import { toast } from 'sonner'
import { questionBankAPI } from '../../lib/api'

interface Question {
  id: string
  text: string
  type: 'multiple-choice' | 'true-false' | 'short-answer' | 'essay' | 'coding'
  subject: string
  topic: string
  difficulty: 'easy' | 'medium' | 'hard'
  tags: string[]
  options?: string[]
  correctAnswer?: string | string[]
  points: number
  timeLimit?: number
  createdBy: string
  createdDate: string
  usageCount: number
  averageScore: number
  lastUsed?: string
  bloomsLevel: string
  learningObjective: string
}

interface Stats {
  total: number
  byDifficulty: { easy: number; medium: number; hard: number }
  byType: {
    'multiple-choice': number
    'true-false': number
    'short-answer': number
    essay: number
    coding: number
  }
  avgUsage: number
  avgScore: number
  subjects: string[]
  tags: string[]
}

function questionTypeLabel(type: string) {
  switch (type) {
    case 'multiple-choice':
      return '≡ƒô¥'
    case 'true-false':
      return 'Γ£ôΓ£ù'
    case 'short-answer':
      return 'Γ£ì∩╕Å'
    case 'essay':
      return '≡ƒôä'
    case 'coding':
      return '≡ƒÆ╗'
    default:
      return 'Γ¥ô'
  }
}

function difficultyColor(d: string) {
  switch (d) {
    case 'easy':
      return 'bg-green-100 text-green-700'
    case 'medium':
      return 'bg-yellow-100 text-yellow-700'
    case 'hard':
      return 'bg-red-100 text-red-700'
    default:
      return 'bg-gray-100 text-gray-700'
  }
}

const defaultForm: {
  text: string
  type: Question['type']
  subject: string
  topic: string
  difficulty: Question['difficulty']
  tags: string
  options: string
  correctAnswer: string
  points: number
  timeLimit: string
  bloomsLevel: string
  learningObjective: string
} = {
  text: '',
  type: 'multiple-choice',
  subject: '',
  topic: '',
  difficulty: 'medium',
  tags: '',
  options: '',
  correctAnswer: '',
  points: 10,
  timeLimit: '',
  bloomsLevel: 'Remember',
  learningObjective: '',
}

export default function QuestionBankManagerPage() {
  const [questions, setQuestions] = useState<Question[]>([])
  const [filteredQuestions, setFilteredQuestions] = useState<Question[]>([])
  const [searchQuery, setSearchQuery] = useState('')
  const [selectedSubject, setSelectedSubject] = useState('all')
  const [selectedDifficulty, setSelectedDifficulty] = useState('all')
  const [selectedType, setSelectedType] = useState('all')
  const [selectedTags, setSelectedTags] = useState<string[]>([])
  const [sortBy, setSortBy] = useState<'date' | 'usage' | 'score' | 'difficulty'>('date')
  const [stats, setStats] = useState<Stats | null>(null)
  const [loading, setLoading] = useState(true)
  const [showAddModal, setShowAddModal] = useState(false)
  const [viewQuestion, setViewQuestion] = useState<Question | null>(null)
  const [editQuestion, setEditQuestion] = useState<Question | null>(null)
  const [form, setForm] = useState(defaultForm)
  const [saving, setSaving] = useState(false)
  const [allSubjects, setAllSubjects] = useState<string[]>([])
  const [allTags, setAllTags] = useState<string[]>([])

  useEffect(() => {
    loadAll()
  }, [])

  useEffect(() => {
    filterQuestions()
  }, [
    questions,
    searchQuery,
    selectedSubject,
    selectedDifficulty,
    selectedType,
    selectedTags,
    sortBy,
  ])

  const loadAll = async () => {
    setLoading(true)
    try {
      const [qData, statsData, subjects, tags] = await Promise.all([
        questionBankAPI.getQuestions(),
        questionBankAPI.getStats(),
        questionBankAPI.getSubjects(),
        questionBankAPI.getTags(),
      ])
      setQuestions(qData || [])
      setStats(statsData)
      setAllSubjects(subjects || [])
      setAllTags(tags || [])
    } catch (e: any) {
      toast.error(e?.response?.data?.detail || 'Failed to load question bank')
    } finally {
      setLoading(false)
    }
  }

  const filterQuestions = () => {
    let filtered = [...questions]
    if (searchQuery) {
      const q = searchQuery.toLowerCase()
      filtered = filtered.filter(
        item =>
          item.text.toLowerCase().includes(q) ||
          item.topic.toLowerCase().includes(q) ||
          item.tags.some(t => t.toLowerCase().includes(q))
      )
    }
    if (selectedSubject !== 'all')
      filtered = filtered.filter(item => item.subject === selectedSubject)
    if (selectedDifficulty !== 'all')
      filtered = filtered.filter(item => item.difficulty === selectedDifficulty)
    if (selectedType !== 'all') filtered = filtered.filter(item => item.type === selectedType)
    if (selectedTags.length > 0) {
      filtered = filtered.filter(item => selectedTags.every(t => item.tags.includes(t)))
    }
    filtered.sort((a, b) => {
      switch (sortBy) {
        case 'usage':
          return b.usageCount - a.usageCount
        case 'score':
          return b.averageScore - a.averageScore
        case 'difficulty': {
          const order = { easy: 1, medium: 2, hard: 3 }
          return order[a.difficulty] - order[b.difficulty]
        }
        case 'date':
        default:
          return new Date(b.createdDate).getTime() - new Date(a.createdDate).getTime()
      }
    })
    setFilteredQuestions(filtered)
  }

  const handleDelete = async (questionId: string) => {
    if (!confirm('Are you sure you want to delete this question?')) return
    try {
      await questionBankAPI.deleteQuestion(questionId)
      toast.success('Question deleted successfully!')
      loadAll()
    } catch (e: any) {
      toast.error(e?.response?.data?.detail || 'Failed to delete question')
    }
  }

  const handleDuplicate = async (question: Question) => {
    try {
      await questionBankAPI.duplicateQuestion(question.id)
      toast.success('Question duplicated successfully!')
      loadAll()
    } catch (e: any) {
      toast.error(e?.response?.data?.detail || 'Failed to duplicate question')
    }
  }

  const handleExport = () => {
    const dataStr = JSON.stringify(filteredQuestions, null, 2)
    const blob = new Blob([dataStr], { type: 'application/json' })
    const url = URL.createObjectURL(blob)
    const link = document.createElement('a')
    link.href = url
    link.download = `question-bank-${new Date().toISOString().split('T')[0]}.json`
    link.click()
    toast.success('Questions exported successfully!')
  }

  const handleImport = () => {
    const input = document.createElement('input')
    input.type = 'file'
    input.accept = '.json'
    input.onchange = async (e: any) => {
      const file = e.target.files?.[0]
      if (!file) return
      try {
        const text = await file.text()
        const imported = JSON.parse(text)
        if (!Array.isArray(imported)) throw new Error('Invalid format')
        let count = 0
        for (const q of imported) {
          await questionBankAPI.createQuestion({
            text: q.text || q.question || '',
            type: q.type || 'multiple-choice',
            subject: q.subject || '',
            topic: q.topic || '',
            difficulty: q.difficulty || 'medium',
            tags: q.tags || [],
            options: q.options,
            correctAnswer: q.correctAnswer ?? q.correct_answer,
            points: q.points || 10,
            timeLimit: q.timeLimit || q.time_limit,
            bloomsLevel: q.bloomsLevel || q.blooms_level || 'Remember',
            learningObjective: q.learningObjective || q.learning_objective || '',
          })
          count++
        }
        toast.success(`Imported ${count} questions successfully!`)
        loadAll()
      } catch {
        toast.error('Failed to import questions. Check file format.')
      }
    }
    input.click()
  }

  const openAddModal = () => {
    setForm(defaultForm)
    setEditQuestion(null)
    setShowAddModal(true)
  }

  const openEditModal = (q: Question) => {
    setEditQuestion(q)
    setForm({
      text: q.text,
      type: q.type,
      subject: q.subject,
      topic: q.topic,
      difficulty: q.difficulty,
      tags: q.tags.join(', '),
      options: q.options?.join(' | ') || '',
      correctAnswer: Array.isArray(q.correctAnswer)
        ? q.correctAnswer.join(', ')
        : q.correctAnswer || '',
      points: q.points,
      timeLimit: q.timeLimit?.toString() || '',
      bloomsLevel: q.bloomsLevel,
      learningObjective: q.learningObjective,
    })
    setShowAddModal(true)
  }

  const handleSave = async () => {
    if (!form.text.trim()) {
      toast.error('Question text is required')
      return
    }
    if (!form.subject.trim()) {
      toast.error('Subject is required')
      return
    }
    const tags = form.tags
      .split(',')
      .map(t => t.trim())
      .filter(Boolean)
    const options =
      form.type === 'multiple-choice' || form.type === 'true-false'
        ? form.options
            .split('|')
            .map(o => o.trim())
            .filter(Boolean)
        : undefined
    const correctAnswer = form.correctAnswer.trim() || undefined
    const timeLimit = form.timeLimit ? parseInt(form.timeLimit) : undefined

    setSaving(true)
    try {
      const payload = {
        text: form.text,
        type: form.type,
        subject: form.subject,
        topic: form.topic,
        difficulty: form.difficulty,
        tags,
        options: options && options.length > 0 ? options : undefined,
        correctAnswer,
        points: form.points,
        timeLimit,
        bloomsLevel: form.bloomsLevel,
        learningObjective: form.learningObjective,
      }

      if (editQuestion) {
        await questionBankAPI.updateQuestion(editQuestion.id, payload)
        toast.success('Question updated successfully!')
      } else {
        await questionBankAPI.createQuestion(payload)
        toast.success('Question created successfully!')
      }
      setShowAddModal(false)
      loadAll()
    } catch (e: any) {
      toast.error(e?.response?.data?.detail || 'Failed to save question')
    } finally {
      setSaving(false)
    }
