// ============================================================================
// AUTH STORE
// ============================================================================

interface AuthState {
  user: User | null
  token: string | null
  isAuthenticated: boolean
}

interface AuthActions {
  login: (user: User, token: string) => void
  logout: () => void
  updateUser: (updates: Partial<User>) => void
  setUser: (user: User) => void // compatibility alias
  setToken: (token: string) => void // compatibility alias
  updatePreferences: (preferences: Partial<UserPreferences>) => void
  refreshSession: () => void
}

export const useAuthStore = create<AuthState & AuthActions>()(
  devtools(
    persist(
      subscribeWithSelector((set, get) => ({
        // State
        user: null,
        token: null,
        isAuthenticated: false,

        // Actions
        login: (user, token) =>
          set({
            user,
            token,
            isAuthenticated: true,
          }),

        logout: () =>
          set({
            user: null,
            token: null,
            isAuthenticated: false,
          }),

        updateUser: updates =>
          set(state => ({
            user: state.user ? { ...state.user, ...updates } : null,
          })),

        updatePreferences: preferences =>
          set(state => ({
            user: state.user
              ? {
                  ...state.user,
                  preferences: { ...state.user.preferences, ...preferences } as UserPreferences,
                }
              : null,
          })),

        // Session refresh: calls refresh endpoint to extend JWT expiry
        refreshSession: async () => {
          try {
            const { default: axios } = await import('axios')
            const token = get().token
            if (!token) return
            const API_URL = (import.meta as any).env?.VITE_API_URL || 'http://localhost:8000'
            const res = await axios.post(
              `${API_URL}/api/auth/refresh`,
              {},
              {
                headers: { Authorization: `Bearer ${token}` },
              }
            )
            if (res.data?.access_token) {
              set({ token: res.data.access_token })
            }
          } catch (e) {
            // Silent fail - token refresh handled by api.ts interceptor
          }
        },

        // Compatibility aliases for legacy code
        setUser: (user: User) =>
          set(() => ({
            user,
            isAuthenticated: true,
          })),
        setToken: (token: string) => set({ token }),
      })),
      {
        name: 'auth-storage',
        partialize: state => ({
          user: state.user,
          token: state.token,
          isAuthenticated: state.isAuthenticated,
        }),
      }
    ),
    { name: 'AuthStore' }
  )
)

// ============================================================================
// EXAM STORE
// ============================================================================

interface ExamState {
  exams: Exam[]
  currentExam: Exam | null
  results: ExamResult[]
  loading: boolean
  error: string | null
}

interface ExamActions {
  setExams: (exams: Exam[]) => void
  setCurrentExam: (exam: Exam | null) => void
  addExam: (exam: Exam) => void
  updateExam: (id: string, updates: Partial<Exam>) => void
  deleteExam: (id: string) => void
  setResults: (results: ExamResult[]) => void
  addResult: (result: ExamResult) => void
  setLoading: (loading: boolean) => void
  setError: (error: string | null) => void
  clearError: () => void
}

export const useExamStore = create<ExamState & ExamActions>()(
  devtools(
    immer(set => ({
      // State
      exams: [],
      currentExam: null,
      results: [],
      loading: false,
      error: null,

      // Actions
      setExams: exams => set({ exams }),

      setCurrentExam: exam => set({ currentExam: exam }),

      addExam: exam =>
        set(state => {
          state.exams.push(exam)
        }),

      updateExam: (id, updates) =>
        set(state => {
          // @ts-expect-error
          const index = state.exams.findIndex((e: any) => e._id === id)
          if (index !== -1) {
            state.exams[index] = { ...state.exams[index], ...updates }
          }
          if (state.currentExam?._id === id) {
            state.currentExam = { ...state.currentExam, ...updates }
          }
        }),

      deleteExam: id =>
        set(state => {
          // @ts-expect-error
          state.exams = state.exams.filter((e: any) => e._id !== id)
          if (state.currentExam?._id === id) {
            state.currentExam = null
          }
        }),

      setResults: results => set({ results }),

      addResult: result =>
        set(state => {
          state.results.push(result)
        }),

      setLoading: loading => set({ loading }),

      setError: error => set({ error }),

      clearError: () => set({ error: null }),
    })),
